// ── Demo mode (admin "showcase"): populate the platform with ~100 tagged demo
// accounts to preview a busy platform, then remove them all in one toggle. ──
let _demoBusy = false; // guard against concurrent seed/teardown
app.get('/api/admin/demo', auth.requireAdmin, async (_req, res) => {
  try {
    const r = await db.query('SELECT COUNT(*)::int AS n FROM users WHERE is_demo = true');
    res.json({ on: r.rows[0].n > 0, count: r.rows[0].n, busy: _demoBusy });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Could not read demo state.' }); }
});
app.post('/api/admin/demo', auth.requireAdmin, async (req, res) => {
  const on = req.body.on === true || req.body.on === 'true';
  if (_demoBusy) return res.status(409).json({ error: 'Demo mode is already updating — give it a moment.' });
  _demoBusy = true;
  try {
    if (on) {
      const existing = await db.query('SELECT COUNT(*)::int AS n FROM users WHERE is_demo = true');
      let count = existing.rows[0].n;
      if (count === 0) count = await demo.seedDemo(db, req.user.id); // idempotent: only seed when empty
      _demoMode = true; await db.setSetting(DEMO_KEY, true);
      adminAudit(req, 'demo.on', 'settings', 'demo_mode', { count });
      res.json({ on: true, count });
    } else {
      const removed = await demo.teardownDemo(db);
      _demoMode = false; await db.setSetting(DEMO_KEY, false);
      adminAudit(req, 'demo.off', 'settings', 'demo_mode', { removed });
      res.json({ on: false, removed });
    }
  } catch (err) { console.error('demo toggle failed:', err); res.status(500).json({ error: 'Could not update demo mode.' }); }
  finally { _demoBusy = false; }
});

app.patch('/api/admin/site', auth.requireAdmin, async (req, res) => {
  await loadSiteLock();
  const s = { ..._siteLock };
  const b = req.body || {};
  // Code length (4–10) regenerates a fresh code at that length.
  if (b.codeLength != null) {
    s.codeLength = Math.max(4, Math.min(10, parseInt(b.codeLength, 10) || 4));
    s.code = genCode(s.codeLength);
  }
  // Explicit custom code (digits only).
  if (typeof b.code === 'string' && b.code.trim()) {
    const c = b.code.trim();
    if (!/^[0-9]{4,10}$/.test(c)) return res.status(400).json({ error: 'Code must be 4–10 digits.' });
    s.code = c;
    s.codeLength = c.length;
  }
  if (b.regenerate) s.code = genCode(s.codeLength || 4);
  // How long a tester stays in after entering the code (0 = single use).
  if (b.passMinutes != null) {
    const n = parseInt(b.passMinutes, 10);
    s.passMinutes = PASS_CHOICES.includes(n) ? n : 0;
  }
  // Timed lock (locks now, auto-unlocks after N minutes).
  if (b.lockForMinutes != null) {
    const m = parseInt(b.lockForMinutes, 10);
    if (m > 0) { s.locked = true; s.lockUntil = new Date(Date.now() + m * 60000).toISOString(); }
  }
  // Immediate lock / unlock switch.
  if (typeof b.locked === 'boolean') {
    s.locked = b.locked;
    if (!b.locked) s.lockUntil = null;
    else if (b.lockForMinutes == null) s.lockUntil = null; // on = indefinite
  }
  if (!s.code) s.code = genCode(s.codeLength || 4);
  try {
    await db.setSetting(SITE_LOCK_KEY, s);
    _siteLock = s;
    adminAudit(req, 'site.lock', 'settings', 'site_lock', { locked: !!s.locked, lockUntil: s.lockUntil || null });
    res.json({
      locked: !!s.locked,
      effectiveLocked: siteLockEffective(),
      lockUntil: s.lockUntil || null,
      code: s.code,
      codeLength: s.codeLength || 4,
      passMinutes: s.passMinutes || 0,
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not save site-lock settings.' });
  }
});

