/* ═══════════════════════════════════════════════
   SOCIAL  —  follow + public posts (AtChat)
   Requires a @username. Posts are public on a user's profile.
═══════════════════════════════════════════════ */
const POSTS_SELECT = `
  SELECT p.id, p.body, p.image, p.images, p.media, p.media_kind, p.created_at, p.edited_at, p.parent_id, p.location, p.reply_scope, p.subscribers_only, p.min_tier_level, p.image_alt, p.ppv_cents,
         (p.promoted_until IS NOT NULL AND p.promoted_until > now()) AS promoted,
         (p.subscribers_only = false OR p.user_id = $1 OR EXISTS(SELECT 1 FROM creator_subs cs LEFT JOIN creator_tiers ct ON ct.id = cs.tier_id WHERE cs.creator_id = p.user_id AND cs.subscriber_id = $1 AND cs.status = 'active' AND (cs.period_end IS NULL OR cs.period_end > now()) AND COALESCE(ct.level, 0) >= p.min_tier_level)) AS sub_ok,
         (COALESCE(p.ppv_cents,0) = 0 OR p.user_id = $1 OR EXISTS(SELECT 1 FROM post_unlocks pu WHERE pu.post_id = p.id AND pu.user_id = $1)) AS ppv_ok,
         u.id AS author_id, u.name AS author_name, u.username AS author_username, u.avatar AS author_avatar, u.verified AS author_verified, u.account_type AS author_type,
         CASE WHEN u.aff_badge_img IS NOT NULL THEN json_build_object(
            'badge', u.aff_badge_img, 'kind', u.aff_badge_kind, 'link', u.aff_link, 'label', u.aff_label,
            'businessId', u.aff_business_id,
            'businessUsername', (SELECT bu.username FROM users bu WHERE bu.id = u.aff_business_id)) END AS author_affiliation,
         (SELECT COUNT(*) FROM post_likes pl WHERE pl.post_id = p.id)::int AS likes,
         (SELECT COUNT(*) FROM posts r WHERE r.parent_id = p.id)::int AS replies,
         (SELECT COUNT(*) FROM post_reposts rp WHERE rp.post_id = p.id)::int AS reposts,
         (SELECT COUNT(*) FROM post_views pv WHERE pv.post_id = p.id)::int AS views,
         EXISTS(SELECT 1 FROM post_likes pl WHERE pl.post_id = p.id AND pl.user_id = $1) AS liked,
         EXISTS(SELECT 1 FROM post_reposts rp WHERE rp.post_id = p.id AND rp.user_id = $1) AS reposted,
         EXISTS(SELECT 1 FROM post_bookmarks bm WHERE bm.post_id = p.id AND bm.user_id = $1) AS bookmarked,
         (SELECT json_build_object('username', ru.username, 'name', ru.name)
            FROM post_reposts rp JOIN users ru ON ru.id = rp.user_id
            WHERE rp.post_id = p.id AND (rp.user_id = $1 OR rp.user_id IN (SELECT following_id FROM follows WHERE follower_id = $1))
            ORDER BY rp.created_at DESC LIMIT 1) AS reposted_by,
         (SELECT json_build_object('id', q.id, 'body', q.body, 'image', q.image, 'media', q.media, 'mediaKind', q.media_kind, 'created_at', q.created_at,
                    'author', json_build_object('id', qu.id, 'name', qu.name, 'username', qu.username, 'avatar', qu.avatar, 'verified', qu.verified, 'accountType', CASE WHEN qu.account_type = 'business' THEN 'business' ELSE 'personal' END))
            FROM posts q JOIN users qu ON qu.id = q.user_id WHERE q.id = p.quote_id) AS quote,
         (p.user_id = $1) AS mine,
         (SELECT json_agg(json_build_object('id', c.id, 'username', c.username, 'name', c.name))
            FROM post_circles pc JOIN circles c ON c.id = pc.circle_id WHERE pc.post_id = p.id) AS circles,
         (SELECT json_agg(json_build_object('id', f.id, 'username', f.username, 'name', f.name))
            FROM post_feeds pf JOIN feeds f ON f.id = pf.feed_id WHERE pf.post_id = p.id) AS feeds,
         (SELECT json_agg(json_build_object('id', o.id, 'text', o.text,
                            'votes', (SELECT COUNT(*)::int FROM post_poll_votes v WHERE v.option_id = o.id)) ORDER BY o.position)
            FROM post_poll_options o WHERE o.post_id = p.id) AS poll_options,
         (SELECT option_id FROM post_poll_votes v WHERE v.post_id = p.id AND v.user_id = $1) AS my_vote,
         (SELECT json_agg(json_build_object('id', tu.id, 'name', tu.name, 'username', tu.username, 'avatar', tu.avatar, 'verified', tu.verified, 'kind', pt.kind))
            FROM post_tags pt JOIN users tu ON tu.id = pt.user_id WHERE pt.post_id = p.id) AS tags
  FROM posts p JOIN users u ON u.id = p.user_id `;
function mapPost(r) {
  let poll = null;
  if (r.poll_options && r.poll_options.length) {
    const total = r.poll_options.reduce((s, o) => s + o.votes, 0);
    poll = { options: r.poll_options, total, myVote: r.my_vote || null };
  }
  // A locked post the viewer can't access — subscriber-only (no active sub) or
  // pay-per-view (not unlocked). Ship a placeholder with no body/media/poll so the
  // viewer sees "subscribe/unlock", not the content.
  const subLocked = !!r.subscribers_only && r.sub_ok === false;
  const ppvLocked = (r.ppv_cents > 0) && r.ppv_ok === false;
  if (subLocked || ppvLocked) {
    return {
      id: r.id, body: '', image: null, images: [], media: null, mediaKind: null,
      created_at: r.created_at, editedAt: null, promoted: false,
      parentId: r.parent_id || null, location: null,
      likes: r.likes, replies: r.replies || 0, liked: false, mine: false,
      reposts: r.reposts || 0, reposted: false, repostedBy: null,
      views: r.views || 0, bookmarked: false, quote: null,
      replyScope: 'everyone', circles: [], feeds: [], poll: null,
      subscribersOnly: !!r.subscribers_only, locked: true, minTierLevel: r.min_tier_level || 0,
      ppvCents: ppvLocked ? r.ppv_cents : undefined, ppvLocked: ppvLocked || undefined,
      author: { id: r.author_id, name: r.author_name, username: r.author_username, avatar: r.author_avatar || null, verified: !!r.author_verified, accountType: r.author_type === 'business' ? 'business' : 'personal', affiliation: r.author_affiliation || null },
    };
  }
  return {
    id: r.id, body: r.body, image: r.image || null,
    images: (Array.isArray(r.images) && r.images.length) ? r.images : (r.image ? [r.image] : []),
    media: r.media || null, mediaKind: r.media_kind || null, created_at: r.created_at,
    subscribersOnly: !!r.subscribers_only, locked: false, minTierLevel: r.min_tier_level || 0, imageAlt: r.image_alt || null,
    ppvCents: r.ppv_cents > 0 ? r.ppv_cents : undefined,
    tagged: Array.isArray(r.tags) ? r.tags.filter((t) => t.kind === 'tag').map(({ kind, ...u }) => u) : [],
    coAuthors: Array.isArray(r.tags) ? r.tags.filter((t) => t.kind === 'author').map(({ kind, ...u }) => u) : [],
    editedAt: r.edited_at || null, promoted: !!r.promoted,
    parentId: r.parent_id || null, location: r.location || null,
    likes: r.likes, replies: r.replies || 0, liked: r.liked, mine: r.mine,
    reposts: r.reposts || 0, reposted: !!r.reposted, repostedBy: r.reposted_by || null,
    views: r.views || 0, bookmarked: !!r.bookmarked, quote: r.quote || null,
    replyScope: r.reply_scope || 'everyone',
    circles: r.circles || [], feeds: r.feeds || [], poll,
    author: { id: r.author_id, name: r.author_name, username: r.author_username, avatar: r.author_avatar || null, verified: !!r.author_verified, accountType: r.author_type === 'business' ? 'business' : 'personal', affiliation: r.author_affiliation || null },
  };
}
// Topic-cluster diversity (the "don't let the feed collapse into one subject /
// one author" pass every big platform runs after ranking). Greedily re-orders an
// already-ranked list so it never stacks the same author back-to-back nor repeats
// a post's primary #hashtag within a short window — pulling the next-best *different*
// item up instead. Falls back to plain rank order when nothing else qualifies, so a
// genuinely one-topic feed is never starved. `tagMap` = postId → [tags].
function diversifyFeed(posts, tagMap) {
  const pool = posts.slice();
  const out = [];
  const TAG_GAP = 3;   // keep the same topic at least this many slots apart
  const primaryTag = (p) => { const t = tagMap[p.id]; return t && t.length ? t[0] : null; };
  while (pool.length) {
    const lastAuthor = out.length ? out[out.length - 1].author.id : null;
    const recentTags = out.slice(-TAG_GAP).map(primaryTag).filter(Boolean);
    let pick = pool.findIndex((p) => {
      if (p.author.id === lastAuthor) return false;          // no back-to-back same author
      const tag = primaryTag(p);
      if (tag && recentTags.includes(tag)) return false;     // space out the same topic
      return true;
    });
    if (pick === -1) pick = 0;                               // nothing clean — don't starve, take the top
    out.push(pool.splice(pick, 1)[0]);
  }
  return out;
}
// Ranking attribution — recompute, per served post, exactly which For You boosts
// fired (mirroring the SQL ORDER BY using the same input sets) plus an approximate
// final score. Powers the admin debug breakdown AND the impression log used to tune
// signal weights from real engagement. `ctx` carries the viewer's signal sets.
function attributeForYou(posts, ctx) {
  const nowMs = Date.now();
  const W = _rankingWeights;
  const recencySec = W.recencyHalfLifeHours * 3600;
  const hasTag = (pid, set) => { const t = ctx.tagMap[pid]; return !!(t && t.some((x) => set.has(x))); };
  return posts.map((p) => {
    if (p.promoted) return { signals: ['promoted'], score: null };
    const aid = p.author.id;
    const sig = [];
    const base = Math.log(1 + (p.likes || 0) + 2 * (p.reposts || 0) + (p.replies || 0)) * 3.0;
    const ageSec = Math.max(0, (nowMs - new Date(p.created_at).getTime()) / 1000);
    let score = base - ageSec / recencySec;
    if (ctx.followedTags.size && hasTag(p.id, ctx.followedTags)) { sig.push('hashtag'); score += W.hashtag; }
    if (ctx.cats.size && (ctx.authorCats.get(aid) || []).some((c) => ctx.cats.has(c))) { sig.push('category'); score += W.category; }
    if (ctx.personalized && ctx.fof.has(aid)) { sig.push('friend_of_friend'); score += W.friendOfFriend; }
    if (ctx.strong.has(aid)) { sig.push('strong_affinity'); score += W.strongAffinity; }
    else if (ctx.mild.has(aid)) { sig.push('mild_affinity'); score += W.mildAffinity; }
    if (ctx.search.size && hasTag(p.id, ctx.search)) { sig.push('recent_search'); score += W.recentSearch; }
    if (ctx.hide.has(aid)) { sig.push('not_interested'); score -= W.notInterested; }
    if (!sig.length) sig.push('base');
    return { signals: sig, score: Math.round(score * 1000) / 1000 };
  });
}
// Log which signals drove the top served impressions (fire-and-forget; never blocks
// the feed response). Pruned to a 14-day window so the table stays bounded.
async function logFeedImpressions(userId, posts, attribution) {
  try {
    // Log EVERY served position (not just the top): the already-seen suppression that
    // powers pagination reads this table, so logging only the top would let posts past
    // that cutoff be re-served on a later page (a near-empty "fresh" page → premature stop).
    const n = Math.min(posts.length, 60);
    if (!n) return;
    const params = [userId];
    const rows = [];
    let i = 2;
    for (let pos = 0; pos < n; pos++) {
      const a = attribution[pos];
      params.push(posts[pos].id, pos, a.signals, a.score);
      rows.push(`($1, $${i}, $${i + 1}, $${i + 2}, $${i + 3})`);
      i += 4;
    }
    await db.query(
      `INSERT INTO feed_impressions (user_id, post_id, position, signals, score) VALUES ${rows.join(', ')}`,
      params
    );
    if (Math.random() < 0.03) {
      await db.query(`DELETE FROM feed_impressions WHERE served_at < now() - interval '14 days'`).catch(() => {});
    }
  } catch (_) { /* observability must never break the feed */ }
}
async function requireHandle(req, res) {
  const me = await chatIdentity(req.user.id);
  if (!me || !me.username) { res.status(403).json(NEED_USERNAME); return null; }
  return me;
}
// Feed mute filter ($1 = viewer): drops muted authors + keyword-matching posts,
// but never the viewer's own posts. Append to a feed WHERE clause.
const MUTE_FILTER = ` AND p.user_id NOT IN (SELECT muted_id FROM post_mutes WHERE muter_id = $1)
  AND (p.user_id = $1 OR NOT EXISTS(SELECT 1 FROM muted_keywords mk WHERE mk.user_id = $1 AND p.body ILIKE '%' || mk.word || '%'))`;
// Hides subscriber-only posts the viewer ($1) can't access from the public feeds
// (they still appear as locked teasers on the creator's own profile).
const SUBONLY_FEED_FILTER = ` AND (p.subscribers_only = false OR p.user_id = $1
  OR EXISTS(SELECT 1 FROM creator_subs cs LEFT JOIN creator_tiers ct ON ct.id = cs.tier_id WHERE cs.creator_id = p.user_id AND cs.subscriber_id = $1 AND cs.status = 'active' AND (cs.period_end IS NULL OR cs.period_end > now()) AND COALESCE(ct.level, 0) >= p.min_tier_level))`;
// Pull #hashtags out of post text (lowercased, deduped, capped).
function extractHashtags(body) {
  const out = new Set();
  const re = /#([\p{L}\p{N}_]{1,50})/gu;
  let m;
  while ((m = re.exec(body || '')) !== null) { out.add(m[1].toLowerCase()); if (out.size >= 10) break; }
  return [...out];
}

/* ── Automated content moderation ──
   Auto-flags clearly-abusive posts into the admin reports queue so a human reviews
   them. A fast heuristic catches explicit violent threats (always on, no key); when
   ANTHROPIC_API_KEY is set, Atwe AI additionally classifies harassment/hate/threats.
   Runs fire-and-forget — it never blocks or fails a post. */
function moderateHeuristic(text) {
  const t = (text || '').toLowerCase();
  if (!t.trim()) return null;
  // Explicit threats of serious violence directed at a person (low false-positive).
  if (/\b(i('?m| am| will| will?)|i'?ll|gonna|going to)\b[^.!?]{0,30}\b(kill|murder|stab|shoot|behead|rape|lynch|hurt|beat|destroy)\b[^.!?]{0,20}\b(you|him|her|them|u|ya|yourself)\b/.test(t)) return 'threat of violence';
  if (/\b(kill|murder|rape|lynch)\s+(yourself|urself)\b/.test(t)) return 'encouraging self-harm';
  return null;
}
async function moderatePost(postId, authorId, text) {
  try {
    if (!text || text.trim().length < 2) return;
    let reason = moderateHeuristic(text);
    if (!reason && process.env.ANTHROPIC_API_KEY) {
      try {
        const sys = 'You are an automated content-safety classifier for a professional social app. Decide if the post contains genuinely abusive content: credible threats of violence, targeted harassment, or hate speech against a protected group. Ordinary criticism, profanity, or strong opinions are NOT abusive. Reply with STRICT JSON only: {"abusive": boolean, "reason": string}. The reason is 2–4 words. Never mention "Claude" or "Anthropic".';
        const msg = await anthropic.messages.create({ model: 'claude-haiku-4-5-20251001', max_tokens: 80, system: sys, messages: [{ role: 'user', content: 'Post: ' + text.slice(0, 1500) }] });
        const out = (msg.content.find((b) => b.type === 'text')?.text || '').trim();
        const parsed = JSON.parse(out.slice(out.indexOf('{'), out.lastIndexOf('}') + 1));
        if (parsed.abusive === true) reason = (typeof parsed.reason === 'string' && parsed.reason.slice(0, 60)) || 'abusive content';
      } catch (e) { /* AI unavailable — heuristic result stands */ }
    }
    if (!reason) return;
    // One open auto-flag per post.
    const exists = await db.query("SELECT 1 FROM reports WHERE target_type = 'post' AND target_id = $1 AND status = 'open'", [postId]);
    if (exists.rowCount) return;
    await db.query(
      "INSERT INTO reports (reporter_id, reported_id, target_type, target_id, note, status, auto) VALUES (NULL, $1, 'post', $2, $3, 'open', true)",
      [authorId, postId, 'Auto-flagged: ' + reason]
    );
  } catch (e) { /* best-effort */ }
}
function extractMentions(body) {
  const out = new Set();
  const re = /@([a-zA-Z0-9_]{2,30})/g;
  let m;
  while ((m = re.exec(body || '')) !== null) out.add(m[1].toLowerCase());
  return [...out];
}
// Can `viewerId` reply to a post given its author + reply_scope + body?
async function canReplyTo(authorId, scope, body, viewerId) {
  if (authorId === viewerId) return true;
  scope = scope || 'everyone';
  if (scope === 'everyone') return true;
  if (scope === 'following') { const f = await db.query('SELECT 1 FROM follows WHERE follower_id = $1 AND following_id = $2', [authorId, viewerId]); return !!f.rows[0]; }
  if (scope === 'mentioned') { const u = await db.query('SELECT username FROM users WHERE id = $1', [viewerId]); const un = ((u.rows[0] && u.rows[0].username) || '').toLowerCase(); return un ? extractMentions(body).includes(un) : false; }
  if (scope === 'verified') { const u = await db.query('SELECT verified FROM users WHERE id = $1', [viewerId]); return !!(u.rows[0] && u.rows[0].verified); }
  return true;
}

// Public profile by @username: identity, counts, follow state, and their posts.
// Lightweight follow counts for the signed-in user (sidebar profile block).
app.get('/api/social/mystats', auth.requireAuth, async (req, res) => {
  try {
    const { rows } = await db.query(
      `SELECT (SELECT COUNT(*)::int FROM follows WHERE following_id = $1) AS followers,
              (SELECT COUNT(*)::int FROM follows WHERE follower_id  = $1) AS following`,
      [req.user.id]
    );
    res.json(rows[0]);
  } catch (err) { res.json({ followers: 0, following: 0 }); }
});

// The followers / following list for a user (by @username).
app.get('/api/social/follows/:username', auth.requireAuth, async (req, res) => {
  const username = (req.params.username || '').trim().replace(/^@/, '');
  const type = req.query.type === 'followers' ? 'followers' : 'following';
  try {
    const t = await db.query('SELECT id FROM users WHERE lower(username) = lower($1)', [username]);
    if (!t.rows[0]) return res.status(404).json({ error: 'User not found.' });
    const uid = t.rows[0].id;
    if (uid !== req.user.id && await blockedEither(req.user.id, uid)) return res.status(404).json({ error: 'User not found.' });
    // followers → people who follow uid; following → people uid follows.
    const sql = type === 'followers'
      ? `SELECT u.id, u.name, u.username, u.avatar, u.verified FROM follows f JOIN users u ON u.id = f.follower_id
         WHERE f.following_id = $1 AND u.username IS NOT NULL AND NOT u.deactivated ORDER BY lower(u.name) LIMIT 200`
      : `SELECT u.id, u.name, u.username, u.avatar, u.verified FROM follows f JOIN users u ON u.id = f.following_id
         WHERE f.follower_id = $1 AND u.username IS NOT NULL AND NOT u.deactivated ORDER BY lower(u.name) LIMIT 200`;
    const { rows } = await db.query(sql, [uid]);
    res.json({ users: rows.map((u) => ({ id: u.id, name: u.name, username: u.username, avatar: u.avatar || null, verified: !!u.verified })) });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

app.get('/api/social/profile/:username', auth.requireAuth, async (req, res) => {
  try {
    if (!(await requireHandle(req, res))) return;
    const handle = (req.params.username || '').replace(/^@/, '');
    const u = await db.query(`SELECT id, name, username, avatar, banner, bio, location, website, contact_email, phone, note, headline, socials, verified, categories, account_type, business_verify_status, otw_visibility, pinned_post_id, sub_price_cents, sub_blurb, created_at, deactivated, connections_visible, business_hours, aff_badge_img, aff_badge_kind, aff_business_id, aff_link, aff_label, (SELECT username FROM users bu WHERE bu.id = users.aff_business_id) AS aff_business_username FROM users WHERE lower(username) = lower($1)`, [handle]);
    if (!u.rows[0]) return res.status(404).json({ error: 'User not found.' });
    const t = u.rows[0];
    // A hibernated (deactivated) account's profile is hidden from everyone but the owner.
    if (t.deactivated && t.id !== req.user.id) return res.status(404).json({ error: 'User not found.' });
    // Blocks are a privacy boundary in BOTH directions — a blocked user must not read
    // the blocker's profile, contact info, or posts. 404 (don't reveal the block).
    if (t.id !== req.user.id && await blockedEither(req.user.id, t.id)) return res.status(404).json({ error: 'User not found.' });
    const [counts, posts, exps, skills, recs, featured, replies] = await Promise.all([
      db.query(
        `SELECT (SELECT COUNT(*)::int FROM follows WHERE following_id = $1) AS followers,
                (SELECT COUNT(*)::int FROM follows WHERE follower_id  = $1) AS following,
                (SELECT COUNT(*)::int FROM posts   WHERE user_id      = $1 AND parent_id IS NULL) AS posts,
                (SELECT COUNT(*)::int FROM connections WHERE (requester_id = $1 OR addressee_id = $1) AND status = 'accepted') AS connections,
                (SELECT status FROM connections WHERE ((requester_id = $2 AND addressee_id = $1) OR (requester_id = $1 AND addressee_id = $2)) LIMIT 1) AS conn_status,
                (SELECT requester_id FROM connections WHERE ((requester_id = $2 AND addressee_id = $1) OR (requester_id = $1 AND addressee_id = $2)) LIMIT 1) AS conn_requester,
                EXISTS(SELECT 1 FROM follows WHERE follower_id = $2 AND following_id = $1) AS is_following,
                EXISTS(SELECT 1 FROM contacts WHERE owner_id = $2 AND contact_id = $1) AS is_contact,
                EXISTS(SELECT 1 FROM blocks WHERE blocker_id = $2 AND blocked_id = $1) AS is_blocked,
                EXISTS(SELECT 1 FROM post_notify WHERE user_id = $2 AND target_id = $1) AS is_notifying`,
        [t.id, req.user.id]
      ),
      db.query(POSTS_SELECT + 'WHERE p.user_id = $2 AND p.parent_id IS NULL AND p.to_main = true AND p.created_at <= now() ORDER BY p.created_at DESC LIMIT 50', [req.user.id, t.id]),
      db.query(
        `SELECT e.id, e.title, e.company, e.company_user_id, e.start_year, e.end_year,
                bu.username AS company_user_username, bu.name AS company_user_name
         FROM experiences e
         LEFT JOIN users bu ON bu.id = e.company_user_id
         WHERE e.user_id = $1
         ORDER BY (e.end_year IS NULL) DESC, COALESCE(e.end_year, 999999) DESC, COALESCE(e.start_year, 0) DESC, e.id DESC`,
        [t.id]
      ),
      db.query(
        `SELECT s.id, s.name, s.assessed,
                (SELECT COUNT(*)::int FROM skill_endorsements e WHERE e.skill_id = s.id) AS endorsements,
                EXISTS(SELECT 1 FROM skill_endorsements e WHERE e.skill_id = s.id AND e.endorser_id = $2) AS endorsed
         FROM user_skills s WHERE s.user_id = $1
         ORDER BY s.assessed DESC, endorsements DESC, s.id`,
        [t.id, req.user.id]
      ),
      db.query(
        `SELECT r.id, r.relationship, r.body, r.status, r.created_at, r.author_id, ${REC_AUTHOR_COLS}
         FROM recommendations r ${REC_AUTHOR_JOIN}
         WHERE r.subject_id = $1 AND r.status = 'visible' ORDER BY r.created_at DESC LIMIT 50`,
        [t.id]
      ),
      db.query(FEATURED_SELECT + 'WHERE f.user_id = $1 ORDER BY f.position ASC, f.created_at DESC LIMIT 50', [t.id]),
      // The user's replies (X-style "Replies" tab) — public replies only.
      db.query(POSTS_SELECT + 'WHERE p.user_id = $2 AND p.parent_id IS NOT NULL AND p.to_main = true AND p.created_at <= now() ORDER BY p.created_at DESC LIMIT 50', [req.user.id, t.id]),
    ]);
    const [edu, certs] = await Promise.all([
      db.query(`SELECT id, school, degree, field, start_year, end_year FROM education WHERE user_id = $1
                ORDER BY COALESCE(end_year, 999999) DESC, COALESCE(start_year, 0) DESC, id DESC`, [t.id]),
      db.query(`SELECT id, name, issuer, issue_year, expire_year, credential_id, url FROM certifications WHERE user_id = $1
                ORDER BY COALESCE(issue_year, 0) DESC, id DESC`, [t.id]),
    ]);
    // Pinned post (top of profile) + whether the viewer has muted this account.
    let pinnedPost = null;
    if (t.pinned_post_id) {
      const pp = await db.query(POSTS_SELECT + 'WHERE p.id = $2 AND p.parent_id IS NULL', [req.user.id, t.pinned_post_id]);
      if (pp.rows[0]) pinnedPost = mapPost(pp.rows[0]);
    }
    const isMuted = t.id !== req.user.id
      ? (await db.query('SELECT 1 FROM post_mutes WHERE muter_id = $1 AND muted_id = $2', [req.user.id, t.id])).rowCount > 0
      : false;
    // Creator-subscription state: their price, and whether I'm an active subscriber.
    const subscriberCount = (t.sub_price_cents > 0)
      ? (await db.query("SELECT COUNT(*)::int AS n FROM creator_subs WHERE creator_id = $1 AND status = 'active' AND (period_end IS NULL OR period_end > now())", [t.id])).rows[0].n
      : 0;
    const subRow = t.id !== req.user.id
      ? (await db.query("SELECT tier_id FROM creator_subs WHERE subscriber_id = $1 AND creator_id = $2 AND status = 'active' AND (period_end IS NULL OR period_end > now())", [req.user.id, t.id])).rows[0]
      : null;
    const isSubscribed = !!subRow;
    // Multi-tier: the creator's active tiers (cheapest first) + which one I'm on.
    const tiers = (await loadCreatorTiers(t.id, {})).map((x) => mapTier(x));
    const myTierId = subRow ? (subRow.tier_id || null) : null;
    // A business account's profile IS its employer page: its posted jobs + the
    // people who currently work there (linked via experiences.company_user_id).
    let businessJobs = [], businessPeople = [];
    if (t.account_type === 'business') {
      const [jb, pp] = await Promise.all([
        db.query(`SELECT ${JOB_COLS}, (SELECT COUNT(*)::int FROM job_applications a WHERE a.job_id = j.id) AS applicants ${JOB_FROM} WHERE j.posted_by = $2 ORDER BY j.created_at DESC LIMIT 40`, [req.user.id, t.id]),
        db.query(`SELECT DISTINCT ON (u.id) u.id, u.name, u.username, u.avatar, u.verified, u.account_type, e.title
                  FROM experiences e JOIN users u ON u.id = e.user_id
                  WHERE e.company_user_id = $1 AND e.end_year IS NULL AND u.username IS NOT NULL
                  ORDER BY u.id, e.start_year DESC NULLS LAST LIMIT 100`, [t.id]),
      ]);
      businessJobs = jb.rows.map((x) => mapJob(x, req.user.id));
      businessPeople = pp.rows.map((u) => ({ id: u.id, name: u.name, username: u.username, avatar: u.avatar || null, verified: !!u.verified, accountType: u.account_type, title: u.title || null }));
    }
    const reviewSummary = t.account_type === 'business' ? await businessReviewSummary(t.id) : null;
    const trustScore = await userTrustScore(t.id); // unified marketplace trust signal
    // Mutual connections: people connected to BOTH me and this profile.
    let mutualConnections = 0;
    if (t.id !== req.user.id) {
      const mc = await db.query(
        `SELECT COUNT(*)::int AS n FROM (
           SELECT CASE WHEN requester_id = $2 THEN addressee_id ELSE requester_id END AS uid
           FROM connections WHERE (requester_id = $2 OR addressee_id = $2) AND status = 'accepted'
           INTERSECT
           SELECT CASE WHEN requester_id = $1 THEN addressee_id ELSE requester_id END AS uid
           FROM connections WHERE (requester_id = $1 OR addressee_id = $1) AND status = 'accepted'
         ) z WHERE uid <> $1 AND uid <> $2`,
        [t.id, req.user.id]
      );
      mutualConnections = mc.rows[0].n;
    }
    // "Followed by people you follow" social proof (X-style): up to 3 of the viewer's
    // follows who also follow this profile (verified first) + the total count.
    let followedBy = [], followedByCount = 0;
    if (t.id !== req.user.id) {
      const fb = await db.query(
        `SELECT ${FOLLOWED_BY_SQL('$2')} AS list,
                (SELECT COUNT(*)::int FROM follows f WHERE f.following_id = $2 AND f.follower_id IN (SELECT following_id FROM follows WHERE follower_id = $1)) AS n`,
        [req.user.id, t.id]
      );
      followedBy = Array.isArray(fb.rows[0].list) ? fb.rows[0].list.filter(Boolean).map((f) => ({ name: f.name, username: f.username, verified: !!f.verified })) : [];
      followedByCount = fb.rows[0].n || 0;
    }
    // "Show your connections" off → hide the count + mutual hint from everyone but
    // the owner (the list endpoint is already gated). Keep the toggle meaningful.
    if (t.connections_visible === false && t.id !== req.user.id) {
      counts.rows[0].connections = null;
      mutualConnections = 0;
    }
    res.json({
      businessJobs, businessPeople, mutualConnections, reviewSummary, trustScore, followedBy, followedByCount,
      user: { id: t.id, name: t.name, username: t.username, avatar: t.avatar || null, banner: t.banner || null, bio: t.bio || null, location: t.location || null, website: t.website || null, contactEmail: t.contact_email || null, phone: t.phone || null, note: t.note || null, headline: t.headline || null, socials: (t.socials && typeof t.socials === 'object' && !Array.isArray(t.socials)) ? t.socials : {}, verified: !!t.verified, categories: Array.isArray(t.categories) ? t.categories : [], accountType: t.account_type === 'business' ? 'business' : 'personal', businessVerified: t.business_verify_status === 'verified', businessVerifyStatus: ['pending','verified'].includes(t.business_verify_status) ? t.business_verify_status : 'none', openToWork: t.otw_visibility === 'everyone', joinedAt: t.created_at || null, businessHours: Array.isArray(t.business_hours) ? t.business_hours : null, affiliation: t.aff_badge_img ? { badge: t.aff_badge_img, kind: t.aff_badge_kind || 'custom', link: t.aff_link || null, label: t.aff_label || null, businessId: t.aff_business_id || null, businessUsername: t.aff_business_username || null } : null },
      experiences: exps.rows.map((e) => ({ id: e.id, title: e.title, company: e.company || e.company_user_name || null, companyUserId: e.company_user_id || null, companyUserUsername: e.company_user_username || null, startYear: e.start_year || null, endYear: e.end_year || null })),
      education: edu.rows.map(mapEducation),
      certifications: certs.rows.map(mapCertification),
      skills: skills.rows.map((s) => ({ id: s.id, name: s.name, endorsements: s.endorsements, endorsed: !!s.endorsed, assessed: !!s.assessed })),
      recommendations: recs.rows.map(mapRec),
      featured: featured.rows.map(mapFeatured),
      replies: replies.rows.map(mapPost),
      counts: { followers: counts.rows[0].followers, following: counts.rows[0].following, posts: counts.rows[0].posts, connections: counts.rows[0].connections },
      connectionState: (t.id === req.user.id) ? 'self'
        : counts.rows[0].conn_status === 'accepted' ? 'connected'
        : counts.rows[0].conn_status === 'pending' ? (counts.rows[0].conn_requester === req.user.id ? 'pending_out' : 'pending_in')
        : 'none',
      pinnedPost, isMuted,
      subPrice: t.sub_price_cents || 0, subBlurb: t.sub_blurb || null, isSubscribed, subscriberCount,
      subTiers: tiers, myTierId,
      isFollowing: counts.rows[0].is_following,
      isContact: counts.rows[0].is_contact,
      isBlocked: counts.rows[0].is_blocked,
      isNotifying: counts.rows[0].is_notifying,
      isMe: t.id === req.user.id,
      posts: posts.rows.map(mapPost),
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

// Follow / unfollow.
app.post('/api/social/follow/:id', auth.requireAuth, rateLimit(120, 60000, 'follow'), async (req, res) => {
  const target = routeId(req.params.id);
  if (!Number.isInteger(target)) return res.status(400).json({ error: 'Invalid user id.' });
  if (target === req.user.id) return res.status(400).json({ error: 'You cannot follow yourself.' });
  try {
    if (!(await requireHandle(req, res))) return;
    const t = await chatIdentity(target);
    if (!t || !t.username) return res.status(404).json({ error: 'User not found.' });
    if (await blockedEither(req.user.id, target)) return res.status(403).json({ error: 'You can’t follow this account.' });
    const f = await db.query(
      'INSERT INTO follows (follower_id, following_id) VALUES ($1, $2) ON CONFLICT DO NOTHING RETURNING following_id',
      [req.user.id, target]
    );
    if (f.rowCount) notify(target, req.user.id, 'follow', null);
    res.json({ ok: true, following: true });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});
app.delete('/api/social/follow/:id', auth.requireAuth, async (req, res) => {
  const target = routeId(req.params.id);
  if (!Number.isInteger(target)) return res.status(400).json({ error: 'Invalid user id.' });
  try {
    await db.query('DELETE FROM follows WHERE follower_id = $1 AND following_id = $2', [req.user.id, target]);
    res.json({ ok: true, following: false });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});
