// Seller sales dashboard: revenue, orders, units, status breakdown, top products,
// and a 14-day sales trend — over the caller's own sales (paid-and-beyond orders).
app.get('/api/shop/analytics', auth.requireAuth, async (req, res) => {
  const PAID = `('paid','fulfilled','escrow','released')`;
  try {
    const head = (await db.query(
      `SELECT COUNT(*)::int AS orders, COALESCE(SUM(total_cents),0)::bigint AS revenue_cents,
              COUNT(*) FILTER (WHERE status = 'pending')::int AS pending,
              COUNT(*) FILTER (WHERE needs_shipping AND shipped_at IS NULL AND status IN ('paid','escrow'))::int AS to_ship
       FROM orders WHERE seller_id = $1 AND status IN ${PAID}`, [req.user.id])).rows[0];
    const units = (await db.query(
      `SELECT COALESCE(SUM(oi.qty),0)::int AS units FROM order_items oi JOIN orders o ON o.id = oi.order_id
       WHERE o.seller_id = $1 AND o.status IN ${PAID}`, [req.user.id])).rows[0].units;
    const top = await db.query(
      `SELECT oi.name, SUM(oi.qty)::int AS units, SUM(oi.qty * oi.price_cents)::bigint AS revenue_cents
       FROM order_items oi JOIN orders o ON o.id = oi.order_id
       WHERE o.seller_id = $1 AND o.status IN ${PAID} GROUP BY oi.name ORDER BY units DESC LIMIT 5`, [req.user.id]);
    const trend = await db.query(
      `SELECT to_char(d::date,'YYYY-MM-DD') AS day, COALESCE(SUM(o.total_cents),0)::bigint AS revenue_cents
       FROM generate_series(now()::date - interval '13 days', now()::date, interval '1 day') d
       LEFT JOIN orders o ON o.seller_id = $1 AND o.status IN ${PAID} AND o.created_at::date = d::date
       GROUP BY d ORDER BY d`, [req.user.id]);
    res.json({
      orders: head.orders, revenueCents: Number(head.revenue_cents), units, pending: head.pending, toShip: head.to_ship,
      topProducts: top.rows.map((r) => ({ name: r.name, units: r.units, revenueCents: Number(r.revenue_cents) })),
      trend: trend.rows.map((r) => ({ day: r.day, revenueCents: Number(r.revenue_cents) })),
    });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Could not load your sales.' }); }
});

/* ═══════════════════════════════════════════════
   BUSINESS REVIEWS & RATINGS
═══════════════════════════════════════════════ */
function mapReview(r, viewerId) {
  return {
    id: r.id, rating: r.rating, body: r.body || '', response: r.response || null, createdAt: r.created_at,
    mine: r.reviewer_id === viewerId,
    reviewer: { id: r.reviewer_id, name: r.reviewer_name, username: r.reviewer_username, avatar: r.reviewer_avatar || null, verified: !!r.reviewer_verified },
  };
}
async function businessReviewSummary(businessId) {
  const r = await db.query('SELECT COUNT(*)::int AS count, COALESCE(AVG(rating), 0)::numeric(3,2) AS avg FROM business_reviews WHERE business_id = $1', [businessId]);
  return { count: r.rows[0].count || 0, average: Number(r.rows[0].avg) || 0 };
}
// Unified per-user trust score (0–100): tenure + completed orders (buyer & seller) +
// ratings received (product reviews as seller, business reviews, and — once Feature 3
// adds them — buyer reviews) + verification. Deterministic, computed on read.
const TRUST_TIERS = [[90, 'Excellent'], [75, 'Great'], [60, 'Good'], [40, 'Fair'], [0, 'New']];
async function userTrustScore(userId) {
  try {
    const u = (await db.query('SELECT created_at, email_verified, verified FROM users WHERE id = $1', [userId])).rows[0];
    if (!u) return null;
    const ageMonths = Math.max(0, (Date.now() - new Date(u.created_at).getTime()) / (30 * 864e5));
    const oc = (await db.query(
      `SELECT COUNT(*) FILTER (WHERE buyer_id = $1 AND status IN ('paid','fulfilled','delivered','released'))::int AS bought,
              COUNT(*) FILTER (WHERE seller_id = $1 AND status IN ('fulfilled','delivered','released'))::int AS sold
         FROM orders WHERE buyer_id = $1 OR seller_id = $1`, [userId])).rows[0];
    const pr = (await db.query('SELECT COUNT(*)::int c, COALESCE(AVG(r.rating),0)::float a FROM product_reviews r JOIN products p ON p.id = r.product_id WHERE p.business_id = $1', [userId])).rows[0];
    const br = (await db.query('SELECT COUNT(*)::int c, COALESCE(AVG(rating),0)::float a FROM business_reviews WHERE business_id = $1', [userId])).rows[0];
    let buyerRev = { c: 0, a: 0 };
    try { buyerRev = (await db.query('SELECT COUNT(*)::int c, COALESCE(AVG(rating),0)::float a FROM buyer_reviews WHERE subject_id = $1', [userId])).rows[0]; } catch (e) { /* table arrives with two-way reviews */ }
    const ratingCount = (pr.c || 0) + (br.c || 0) + (buyerRev.c || 0);
    const ratingAvg = ratingCount ? ((pr.a * pr.c + br.a * br.c + buyerRev.a * buyerRev.c) / ratingCount) : 0;
    const completed = (oc.bought || 0) + (oc.sold || 0);
    let score = 0;
    score += Math.min(20, ageMonths * 2);                                   // tenure (≤20)
    score += Math.min(30, completed * 3);                                   // marketplace activity (≤30)
    score += ratingCount ? (ratingAvg / 5) * 40 * Math.min(1, ratingCount / 5) : 0; // ratings, ramped (≤40)
    score += (u.email_verified ? 5 : 0) + (u.verified ? 5 : 0);            // verification (≤10)
    score = Math.max(0, Math.min(100, Math.round(score)));
    const tier = (TRUST_TIERS.find(([t]) => score >= t) || [0, 'New'])[1];
    return { score, tier, completedOrders: completed, ratingAvg: Math.round(ratingAvg * 10) / 10, ratingCount };
  } catch (e) { return null; }
}
// Leave or update a review for a business (1:1 per reviewer; upsert).
app.post('/api/business/:id/reviews', auth.requireAuth, rateLimit(20, 60000, 'review'), async (req, res) => {
  const id = routeId(req.params.id);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid business id.' });
  const rating = parseInt(req.body.rating, 10);
  if (!Number.isInteger(rating) || rating < 1 || rating > 5) return res.status(400).json({ error: 'Pick a rating from 1 to 5 stars.' });
  const body = (req.body.body || '').trim().slice(0, 2000);
  try {
    if (id === req.user.id) return res.status(400).json({ error: 'You can’t review your own business.' });
    const b = await db.query('SELECT account_type FROM users WHERE id = $1', [id]);
    if (!b.rows[0]) return res.status(404).json({ error: 'Business not found.' });
    if (b.rows[0].account_type !== 'business') return res.status(400).json({ error: 'Only business accounts can be reviewed.' });
    if (await blockedEither(req.user.id, id)) return res.status(403).json({ error: 'You can’t review this business.' });
    // A new review (not an edit) resets any existing business response.
    await db.query(
      `INSERT INTO business_reviews (business_id, reviewer_id, rating, body) VALUES ($1,$2,$3,$4)
       ON CONFLICT (business_id, reviewer_id) DO UPDATE SET rating = $3, body = $4, response = NULL, created_at = now()`,
      [id, req.user.id, rating, body]
    );
    notify(id, req.user.id, 'review');
    res.json({ ok: true });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Could not save your review.' }); }
});
// Reviews for a business (public) + summary + my own review.
app.get('/api/business/:id/reviews', auth.requireAuth, async (req, res) => {
  const id = routeId(req.params.id);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid business id.' });
  try {
    const { rows } = await db.query(
      `SELECT r.id, r.rating, r.body, r.response, r.created_at, r.reviewer_id,
              u.name AS reviewer_name, u.username AS reviewer_username, u.avatar AS reviewer_avatar, u.verified AS reviewer_verified
       FROM business_reviews r JOIN users u ON u.id = r.reviewer_id
       WHERE r.business_id = $1 ORDER BY (r.reviewer_id = $2) DESC, r.created_at DESC LIMIT 200`,
      [id, req.user.id]
    );
    const summary = await businessReviewSummary(id);
    res.json({ reviews: rows.map((r) => mapReview(r, req.user.id)), summary, mine: rows.find((r) => r.reviewer_id === req.user.id) ? mapReview(rows.find((r) => r.reviewer_id === req.user.id), req.user.id) : null });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Could not load reviews.' }); }
});
