const mapSearchUser = (u) => ({ id: u.id, name: u.name, username: u.username, avatar: u.avatar || null, verified: u.verified, categories: Array.isArray(u.categories) ? u.categories : [], accountType: u.account_type === 'business' ? 'business' : 'personal', businessVerified: u.business_verify_status === 'verified', headline: u.headline || null });
// Lightweight @mention autocomplete: a few users whose @username/name starts with
// (or contains) the typed prefix. Prefix matches rank first; blocked users excluded.
app.get('/api/social/mention-search', auth.requireAuth, async (req, res) => {
  const q = String(req.query.q || '').trim().replace(/^@/, '').toLowerCase().slice(0, 30);
  if (!q) return res.json({ users: [] });
  try {
    const { rows } = await db.query(
      `SELECT id, name, username, avatar, verified, account_type, business_verify_status FROM users
       WHERE username IS NOT NULL AND NOT deactivated AND (lower(username) LIKE $1 || '%' OR lower(name) LIKE '%' || $1 || '%')
         AND id NOT IN (SELECT blocked_id FROM blocks WHERE blocker_id = $2)
         AND id NOT IN (SELECT blocker_id FROM blocks WHERE blocked_id = $2)
       ORDER BY (lower(username) = $1) DESC, (lower(username) LIKE $1 || '%') DESC, lower(username) LIMIT 6`,
      [q, req.user.id]
    );
    res.json({ users: rows.map((u) => ({ id: u.id, name: u.name, username: u.username, avatar: u.avatar || null, verified: !!u.verified, accountType: u.account_type === 'business' ? 'business' : 'personal' })) });
  } catch (err) { console.error(err); res.json({ users: [] }); }
});
// Parse X-style search operators out of a query into a filter object. Unknown
// tokens stay as free text. Validates dates and numbers; bad values are ignored.
function parsePostSearch(raw) {
  const f = { text: '', from: null, tag: null, since: null, until: null, hasMedia: false, hasImage: false, hasVideo: false, minLikes: null, minReposts: null, sort: 'latest' };
  const words = [];
  const DATE_RE = /^\d{4}-\d{2}-\d{2}$/;
  for (const tok of String(raw || '').trim().split(/\s+/)) {
    if (!tok) continue;
    const m = tok.match(/^([a-z_]+):(.+)$/i);
    if (m) {
      const k = m[1].toLowerCase(), v = m[2];
      if (k === 'from') { f.from = v.replace(/^@/, '').slice(0, 40); continue; }
      if (k === 'since' && DATE_RE.test(v) && !isNaN(Date.parse(v))) { f.since = v; continue; }
      if (k === 'until' && DATE_RE.test(v) && !isNaN(Date.parse(v))) { f.until = v; continue; }
      if (k === 'has') { const lv = v.toLowerCase(); if (lv === 'image' || lv === 'photo') f.hasImage = true; else if (lv === 'video') f.hasVideo = true; else if (lv === 'media') f.hasMedia = true; continue; }
      if ((k === 'min_likes' || k === 'minlikes') && /^\d+$/.test(v)) { f.minLikes = Math.min(parseInt(v, 10), 1e9); continue; }
      if ((k === 'min_reposts' || k === 'minreposts') && /^\d+$/.test(v)) { f.minReposts = Math.min(parseInt(v, 10), 1e9); continue; }
      if (k === 'sort' && (v === 'top' || v === 'latest')) { f.sort = v; continue; }
    }
    if (tok[0] === '#' && tok.length > 1) { f.tag = tok.slice(1).toLowerCase().replace(/[^\p{L}\p{N}_]/gu, ''); continue; }
    words.push(tok);
  }
  f.text = words.join(' ').trim();
  return f;
}
app.get('/api/search', auth.requireAuth, async (req, res) => {
  const q = (req.query.q || '').trim().replace(/^@/, '');
  const scope = req.query.scope || '';
  if (!q) return res.json({});
  const like = '%' + q.replace(/[%_\\]/g, '\\$&') + '%';
  const me = req.user.id;
  try {
    if (!(await requireHandle(req, res))) return;
    if (scope === 'posts') {
      // X-style operators: from:user  since:YYYY-MM-DD  until:YYYY-MM-DD
      // has:media|image|video  min_likes:N  min_reposts:N  #tag  @mention.
      const f = parsePostSearch(req.query.q || '');
      const where = ['p.parent_id IS NULL', 'p.to_main = true', 'p.created_at <= now()'];
      const params = [me];
      if (f.text) { params.push('%' + f.text.replace(/[%_\\]/g, '\\$&') + '%'); where.push(`p.body ILIKE $${params.length}`); }
      if (f.from) { params.push(f.from); where.push(`p.user_id = (SELECT id FROM users WHERE lower(username) = lower($${params.length}))`); }
      if (f.tag) { params.push(f.tag); where.push(`EXISTS(SELECT 1 FROM post_hashtags h WHERE h.post_id = p.id AND h.tag = lower($${params.length}))`); }
      if (f.since) { params.push(f.since); where.push(`p.created_at >= $${params.length}`); }
      if (f.until) { params.push(f.until); where.push(`p.created_at < ($${params.length}::date + interval '1 day')`); }
      if (f.hasImage) where.push(`p.image IS NOT NULL`);
      if (f.hasVideo) where.push(`p.media_kind = 'video'`);
      if (f.hasMedia) where.push(`(p.image IS NOT NULL OR p.media IS NOT NULL)`);
      if (f.minLikes != null) { params.push(f.minLikes); where.push(`(SELECT COUNT(*) FROM post_likes pl WHERE pl.post_id = p.id) >= $${params.length}`); }
      if (f.minReposts != null) { params.push(f.minReposts); where.push(`(SELECT COUNT(*) FROM post_reposts rp WHERE rp.post_id = p.id) >= $${params.length}`); }
      // Need at least one real constraint beyond the base (avoid dumping the whole feed).
      if (!f.text && !f.from && !f.tag && !f.since && !f.until && !f.hasMedia && !f.hasImage && !f.hasVideo && f.minLikes == null && f.minReposts == null) {
        return res.json({ posts: [] });
      }
      const order = f.sort === 'top'
        ? `ORDER BY (SELECT COUNT(*) FROM post_likes pl WHERE pl.post_id = p.id) DESC, p.created_at DESC`
        : `ORDER BY p.created_at DESC`;
      const r = await db.query(POSTS_SELECT + 'WHERE ' + where.join(' AND ') + ' ' + order + ' LIMIT 40', params);
      return res.json({ posts: r.rows.map(mapPost) });
    }
    if (scope === 'circles') {
      const r = await db.query(
        `SELECT c.id, c.username, c.name, c.bio, c.avatar, c.created_by,
                (SELECT COUNT(*)::int FROM circle_members m WHERE m.circle_id = c.id) AS members,
                EXISTS(SELECT 1 FROM circle_members m WHERE m.circle_id = c.id AND m.user_id = $1) AS is_member
         FROM circles c WHERE c.name ILIKE $2 OR c.username ILIKE $2 ORDER BY members DESC, c.name LIMIT 30`,
        [me, like]
      );
      return res.json({ circles: r.rows.map((c) => ({ id: c.id, username: c.username, name: c.name, bio: c.bio || null, avatar: c.avatar || null, members: c.members, isMember: c.is_member, isAdmin: c.created_by === me })) });
    }
    if (scope === 'feeds') {
      const r = await db.query(
        `SELECT f.id, f.username, f.name, f.bio, f.avatar, f.open, f.created_by,
                (SELECT COUNT(*)::int FROM feed_members m WHERE m.feed_id = f.id) AS members,
                EXISTS(SELECT 1 FROM feed_members m WHERE m.feed_id = f.id AND m.user_id = $1) AS is_member,
                EXISTS(SELECT 1 FROM feed_requests rq WHERE rq.feed_id = f.id AND rq.user_id = $1) AS requested
         FROM feeds f WHERE f.name ILIKE $2 OR f.username ILIKE $2 ORDER BY members DESC, f.name LIMIT 30`,
        [me, like]
      );
      return res.json({ feeds: r.rows.map((f) => ({ id: f.id, username: f.username, name: f.name, bio: f.bio || null, avatar: f.avatar || null, open: f.open, members: f.members, isMember: f.is_member, isAdmin: f.created_by === me, requested: f.requested })) });
    }
    if (scope === 'chats') {
      const r = await db.query(
        `SELECT m.id, m.body, m.created_at,
                (CASE WHEN m.sender_id = $1 THEN m.recipient_id ELSE m.sender_id END) AS peer_id,
                u.name AS peer_name, u.username AS peer_username, u.avatar AS peer_avatar
         FROM at_messages m
         JOIN users u ON u.id = (CASE WHEN m.sender_id = $1 THEN m.recipient_id ELSE m.sender_id END)
         WHERE (m.sender_id = $1 OR m.recipient_id = $1) AND m.body ILIKE $2
         ORDER BY m.created_at DESC LIMIT 30`,
        [me, like]
      );
      return res.json({ messages: r.rows.map((m) => ({ id: m.id, body: m.body, created_at: m.created_at, peer: { id: m.peer_id, name: m.peer_name, username: m.peer_username, avatar: m.peer_avatar || null } })) });
    }
    if (scope === 'groups') {
      const r = await db.query(
        `SELECT g.id, g.name, g.username, g.avatar,
                (SELECT COUNT(*)::int FROM at_group_members m WHERE m.group_id = g.id) AS members
         FROM at_groups g JOIN at_group_members me2 ON me2.group_id = g.id AND me2.user_id = $1
         WHERE g.name ILIKE $2 OR g.username ILIKE $2 ORDER BY g.name LIMIT 30`,
        [me, like]
      );
      return res.json({ groups: r.rows.map((g) => ({ id: g.id, name: g.name, username: g.username || null, avatar: g.avatar || null, members: g.members })) });
    }
    // Businesses scope: official business accounts (the company@username pages are
    // retired — a business is a real Atwe account now).
    if (scope === 'businesses' || scope === 'companies') {
      const r = await db.query(
        `SELECT id, name, username, avatar, verified, categories, account_type, headline, business_verify_status FROM users
         WHERE account_type = 'business' AND username IS NOT NULL AND NOT deactivated AND (
           username ILIKE $1 OR name ILIKE $1
           OR EXISTS (SELECT 1 FROM jsonb_array_elements_text(categories) c WHERE c ILIKE $1)
         )
         ORDER BY (lower(username) = lower($2)) DESC, (username ILIKE $1) DESC, lower(name) LIMIT 40`,
        [like, q]
      );
      return res.json({ businesses: r.rows.map(mapSearchUser) });
    }
    // Shop scope: marketplace listings (items / services) matched by name/description.
    if (scope === 'shop') {
      const r = await db.query(
        `${LISTING_SELECT} WHERE p.active = true AND (p.name ILIKE $1 OR p.description ILIKE $1)
           AND p.business_id NOT IN (SELECT blocked_id FROM blocks WHERE blocker_id = $2)
           AND p.business_id NOT IN (SELECT blocker_id FROM blocks WHERE blocked_id = $2)
         ORDER BY (p.name ILIKE $1) DESC, p.created_at DESC LIMIT 40`,
        [like, req.user.id]
      );
      return res.json({ listings: r.rows.map(mapListing) });
    }
    // People scope: professionals matched by name, @username, or industry.
    if (scope === 'people') {
      // Personalized: among matches, rank people in your network first (followed by
      // people you follow), then verified, then the name/handle match quality. Each
      // row also carries "Followed by people you follow" social proof.
      const r = await db.query(
        `SELECT id, name, username, avatar, verified, categories, account_type, headline, business_verify_status,
                (SELECT COUNT(*)::int FROM follows f WHERE f.following_id = users.id AND f.follower_id IN (SELECT following_id FROM follows WHERE follower_id = $3)) AS mutuals,
                ${FOLLOWED_BY_SQL('users.id', '$3')} AS followed_by
         FROM users
         WHERE username IS NOT NULL AND id <> $3 AND NOT deactivated AND (
           username ILIKE $1 OR name ILIKE $1
           OR EXISTS (SELECT 1 FROM jsonb_array_elements_text(categories) c WHERE c ILIKE $1)
         )
         ORDER BY (lower(username) = lower($2)) DESC, mutuals DESC, verified DESC, (username ILIKE $1) DESC, lower(username) LIMIT 40`,
        [like, q, me]
      );
      return res.json({ users: r.rows.map((u) => ({ ...mapSearchUser(u), ...socialProof(u) })) });
    }
    // Default ('all'): people + posts + a few marketplace listings.
    const [users, posts, listings] = await Promise.all([
      db.query(
        `SELECT id, name, username, avatar, verified, categories, account_type, headline, business_verify_status FROM users
         WHERE username IS NOT NULL AND NOT deactivated AND (
           username ILIKE $1 OR name ILIKE $1
           OR EXISTS (SELECT 1 FROM jsonb_array_elements_text(categories) c WHERE c ILIKE $1)
         )
         ORDER BY (lower(username) = lower($2)) DESC, (username ILIKE $1) DESC, lower(username) LIMIT 20`,
        [like, q]
      ),
      db.query(
        POSTS_SELECT + `WHERE p.parent_id IS NULL AND p.to_main = true AND p.created_at <= now() AND p.body ILIKE $2 ORDER BY p.created_at DESC LIMIT 20`,
        [me, like]
      ),
      db.query(
        `${LISTING_SELECT} WHERE p.active = true AND (p.name ILIKE $1 OR p.description ILIKE $1)
           AND p.business_id NOT IN (SELECT blocked_id FROM blocks WHERE blocker_id = $2)
           AND p.business_id NOT IN (SELECT blocker_id FROM blocks WHERE blocked_id = $2)
         ORDER BY (p.name ILIKE $1) DESC, p.created_at DESC LIMIT 8`,
        [like, me]
      ),
    ]);
    res.json({
      users: users.rows.map(mapSearchUser),
      posts: posts.rows.map(mapPost),
      listings: listings.rows.map(mapListing),
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Search failed. Please try again.' });
  }
});

/* ═══════════════════════════════════════════════
   PLAN  —  authoritative, server-side
═══════════════════════════════════════════════ */
app.put('/api/plan', auth.requireAuth, async (req, res) => {
  const plan = req.body.plan === 'pro' ? 'pro' : 'free';
  try {
    // Atomic transition: a row is returned only when the plan actually changes,
    // so concurrent upgrades (e.g. webhook + this call) can't double-send the email.
    const { rows } = await db.query(
      'UPDATE users SET plan = $1 WHERE id = $2 AND plan IS DISTINCT FROM $1 RETURNING name, email',
      [plan, req.user.id]
    );
    res.json({ plan });

    // Newly upgraded to Pro → confirm by email (best-effort, only on transition).
    if (plan === 'pro' && rows[0]) {
      try {
        await sendProWelcomeEmail(rows[0]);
      } catch (e) {
        console.error('Pro welcome email failed:', e.message);
      }
    }
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

/* ═══════════════════════════════════════════════
   BILLING  —  Stripe Checkout (webhook is mounted near the top)
═══════════════════════════════════════════════ */
app.post('/api/billing/checkout', auth.requireAuth, async (req, res) => {
  if (!billing.isConfigured()) {
    return res.status(503).json({ error: 'Billing not configured' });
  }
  try {
    const { rows } = await db.query(
      'SELECT id, email, stripe_customer_id FROM users WHERE id = $1',
      [req.user.id]
    );
    const user = rows[0];
    if (!user) return res.status(404).json({ error: 'Account not found.' });

    const origin = `${req.protocol}://${req.get('host')}`;
    const session = await billing.createCheckoutSession(user, {
      successUrl: `${origin}/?checkout=success`,
      cancelUrl: `${origin}/?checkout=cancel`,
    });
    res.json({ url: session.url });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

/* ═══════════════════════════════════════════════
   REFUNDS & HELP CENTER
   A member reports a problem with a payment they made and requests a refund;
   staff (the `refunds` scope) review and approve (money reversed to the member's
   wallet) or decline. Platform charges (ad/boost/promote/pro) + orders + tips are
   refundable; a wrong peer-to-peer SEND is NOT auto-reversible (the money is in the
   recipient's balance and may be spent — same as Venmo/Cash App), so those route to
   a "request the recipient return it" nudge instead (see /api/wallet/return-request).
═══════════════════════════════════════════════ */
const REFUND_KINDS = ['ad', 'boost', 'promote', 'pro', 'order', 'tip'];
// Validate that `refId` is a real payment the caller actually made, and return the
// amount they paid (so a member can't request a refund on someone else's payment or
// invent an amount). Platform charges resolve via the company_revenue ledger; orders
// + tips via their own tables. Returns { amountCents } or null.
async function refundVerifyPayment(userId, kind, refId) {
  try {
    if (['ad', 'boost', 'promote', 'pro'].includes(kind)) {
      const r = await db.query(
        `SELECT amount_cents FROM company_revenue WHERE source = $1 AND ref_id = $2 AND payer_id = $3 AND amount_cents > 0 ORDER BY created_at DESC LIMIT 1`,
        [kind, String(refId), userId]);
      return r.rows[0] ? { amountCents: r.rows[0].amount_cents } : null;
    }
    if (kind === 'order') {
      const r = await db.query(`SELECT total_cents, status FROM orders WHERE id = $1 AND buyer_id = $2`, [parseInt(refId, 10), userId]);
      const o = r.rows[0];
      if (!o) return null;
      if (['refunded', 'cancelled'].includes(o.status)) return { amountCents: o.total_cents || 0, alreadyDone: true };
      return { amountCents: o.total_cents || 0 };
    }
    if (kind === 'tip') {
      const r = await db.query(`SELECT amount_cents FROM tips WHERE id = $1 AND from_id = $2`, [parseInt(refId, 10), userId]);
      return r.rows[0] ? { amountCents: r.rows[0].amount_cents } : null;
    }
  } catch (_) { /* fall through */ }
  return null;
}
// Actually move the money for an approved refund: credit the member's wallet, and for
// company-revenue-backed charges write a negative ledger row so the Revenue dashboard
// nets it out. For an order, also flip it to `refunded`. Idempotent-ish via the status
// guard on the request row (the caller only calls this once, inside the resolve route).
async function executeRefund(reqRow, amountCents, adminId) {
  const uid = reqRow.user_id;
  await walletCreditStandalone(uid, amountCents, 'refund', 'Refund · ' + reqRow.kind);
  if (['ad', 'boost', 'promote', 'pro', 'tip'].includes(reqRow.kind)) {
    // Negative company_revenue row = the platform gave money back (nets the dashboard).
    await db.query(
      'INSERT INTO company_revenue (source, ref_id, payer_id, payer_name, amount_cents, note) VALUES ($1,$2,$3,(SELECT name FROM users WHERE id=$3),$4,$5)',
      ['refund', reqRow.ref_id, uid, -Math.abs(amountCents), 'Refund of ' + reqRow.kind]
    ).catch(() => {});
  }
  if (reqRow.kind === 'order') {
    await db.query(`UPDATE orders SET status='refunded' WHERE id=$1 AND status NOT IN ('refunded','cancelled')`, [parseInt(reqRow.ref_id, 10)]).catch(() => {});
  }
}

// Member files a refund request against a payment they made.
app.post('/api/refunds', auth.requireAuth, rateLimit(20, 60000, 'refund-req'), async (req, res) => {
  const kind = String(req.body.kind || '').trim();
  const refId = req.body.refId != null ? String(req.body.refId) : '';
  const reason = (req.body.reason ? String(req.body.reason) : '').slice(0, 800);
  if (!REFUND_KINDS.includes(kind) || !refId) return res.status(400).json({ error: 'Tell us which payment this is about.' });
  try {
    const pay = await refundVerifyPayment(req.user.id, kind, refId);
    if (!pay) return res.status(404).json({ error: 'We couldn’t find that payment on your account.' });
    if (pay.alreadyDone) return res.status(400).json({ error: 'That order was already refunded or cancelled.' });
    const { rows } = await db.query(
      `INSERT INTO refund_requests (user_id, kind, ref_id, amount_cents, reason) VALUES ($1,$2,$3,$4,$5)
       ON CONFLICT (user_id, kind, ref_id) WHERE status = 'open' DO NOTHING
       RETURNING id, kind, ref_id, amount_cents, status, created_at`,
      [req.user.id, kind, refId, pay.amountCents, reason || null]);
    if (!rows[0]) return res.status(409).json({ error: 'You already have an open request for this payment.' });
    logEvent('money', 'refund.requested', { req, subjectType: 'refund', subjectId: rows[0].id, meta: { kind, amountCents: pay.amountCents } });
    res.status(201).json({ request: rows[0] });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
// Member sees their own refund requests + status.
app.get('/api/refunds', auth.requireAuth, async (req, res) => {
  try {
    const { rows } = await db.query(
      `SELECT id, kind, ref_id, amount_cents, reason, status, resolution_note, refunded_cents, created_at, resolved_at
       FROM refund_requests WHERE user_id = $1 ORDER BY created_at DESC LIMIT 100`, [req.user.id]);
    res.json({ requests: rows });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
// The member's recent refundable payments (to populate the "request a refund" picker).
app.get('/api/refunds/eligible', auth.requireAuth, async (req, res) => {
  try {
    const charges = await db.query(
      `SELECT source AS kind, ref_id, amount_cents, created_at FROM company_revenue
       WHERE payer_id = $1 AND source IN ('ad','boost','promote','pro') AND amount_cents > 0
       ORDER BY created_at DESC LIMIT 30`, [req.user.id]).then(r => r.rows).catch(() => []);
    const orders = await db.query(
      `SELECT id::text AS ref_id, total_cents AS amount_cents, created_at FROM orders
       WHERE buyer_id = $1 AND status IN ('paid','fulfilled','delivered','released') ORDER BY created_at DESC LIMIT 20`, [req.user.id]).then(r => r.rows.map(o => ({ kind: 'order', ...o }))).catch(() => []);
    const tips = await db.query(
      `SELECT id::text AS ref_id, amount_cents, created_at FROM tips WHERE from_id = $1 ORDER BY created_at DESC LIMIT 20`, [req.user.id]).then(r => r.rows.map(t => ({ kind: 'tip', ...t }))).catch(() => []);
    // Hide ones that already have an open/handled request.
    const open = await db.query(`SELECT kind, ref_id FROM refund_requests WHERE user_id = $1 AND status = 'open'`, [req.user.id]).then(r => new Set(r.rows.map(x => x.kind + ':' + x.ref_id))).catch(() => new Set());
    const items = [...charges, ...orders, ...tips].filter(x => !open.has(x.kind + ':' + x.ref_id))
      .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
    res.json({ items });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
// Peer-to-peer "wrong send" — we don't force-claw money already in someone's balance
// (it may be spent). Instead notify the recipient with a polite return request.
app.post('/api/wallet/return-request', auth.requireAuth, rateLimit(10, 60000, 'return-req'), async (req, res) => {
  const txId = parseInt(req.body.txId, 10);
  if (!Number.isInteger(txId)) return res.status(400).json({ error: 'Which payment?' });
  try {
    const r = await db.query(`SELECT peer_id, delta_cents FROM wallet_tx WHERE id = $1 AND user_id = $2 AND kind = 'send' AND delta_cents < 0`, [txId, req.user.id]);
    const tx = r.rows[0];
    if (!tx || !tx.peer_id) return res.status(404).json({ error: 'We couldn’t find that transfer.' });
    notify(tx.peer_id, req.user.id, 'return_request');
    res.json({ ok: true });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});

// Appeal a suspension / ban. A locked-out member can't log in, so this is public —
// they re-prove the password (like login), and we only accept an appeal for an
// actually suspended/banned account. One open appeal at a time; staff review it.
app.post('/api/auth/appeal', rateLimit(5, 3600000, 'appeal'), async (req, res) => {
  const identifier = (req.body.identifier || req.body.email || '').trim().toLowerCase().replace(/^@/, '');
  const password = req.body.password || '';
  const message = (req.body.message ? String(req.body.message) : '').slice(0, 1500);
  if (!identifier || !password) return res.status(400).json({ error: 'Enter your email/username and password.' });
  try {
    const { rows } = await db.query('SELECT id, password_hash, status FROM users WHERE lower(email) = $1 OR lower(username) = $1', [identifier]);
    const user = rows[0];
    const ok = await auth.verifyPassword(password, user ? user.password_hash : auth.DUMMY_HASH);
    if (!user || !ok) return res.status(401).json({ error: 'Invalid email/username or password.' });
    if (user.status !== 'suspended' && user.status !== 'banned') return res.status(400).json({ error: 'This account isn’t suspended or banned, so there’s nothing to appeal.' });
    const ins = await db.query(
      `INSERT INTO appeals (user_id, status_kind, message) VALUES ($1,$2,$3)
       ON CONFLICT (user_id) WHERE state = 'open' DO NOTHING RETURNING id`,
      [user.id, user.status, message || null]);
    if (!ins.rows[0]) return res.status(409).json({ error: 'You already have an appeal under review.' });
    logEvent('account', 'appeal.filed', { actorId: user.id, subjectType: 'user', subjectId: user.id, meta: { statusKind: user.status } });
    res.status(201).json({ ok: true });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});

// GDPR/CCPA data-subject request — a member formally asks for a copy of their data
// or account erasure. Tracked to a legal deadline; the actual export/delete is done
// with the existing tools, this is the compliance record. (Self-serve export lives
// at /api/account/export; deactivate at /api/account/deactivate.)
const DATA_REQ_KINDS = ['export', 'delete'];
const DSAR_DEADLINE_DAYS = 30;
app.post('/api/data-requests', auth.requireAuth, rateLimit(5, 3600000, 'data-req'), async (req, res) => {
  const kind = String(req.body.kind || '').trim();
  const note = (req.body.note ? String(req.body.note) : '').slice(0, 1000) || null;
  if (!DATA_REQ_KINDS.includes(kind)) return res.status(400).json({ error: 'Choose “export” or “delete”.' });
  try {
    const due = new Date(Date.now() + DSAR_DEADLINE_DAYS * 86400000);
    const { rows } = await db.query(
      `INSERT INTO data_requests (user_id, email, kind, note, due_at)
       VALUES ($1, (SELECT email FROM users WHERE id=$1), $2, $3, $4)
       ON CONFLICT (user_id, kind) WHERE state = 'open' DO NOTHING
       RETURNING id, kind, state, due_at, created_at`,
      [req.user.id, kind, note, due]);
    if (!rows[0]) return res.status(409).json({ error: 'You already have a request of this type in progress.' });
    logEvent('compliance', 'data_request.filed', { req, subjectType: 'user', subjectId: req.user.id, meta: { kind } });
    res.status(201).json({ request: rows[0] });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
app.get('/api/data-requests', auth.requireAuth, async (req, res) => {
  try {
    const { rows } = await db.query(
      `SELECT id, kind, note, state, resolution_note, due_at, created_at, resolved_at FROM data_requests WHERE user_id = $1 ORDER BY created_at DESC LIMIT 50`, [req.user.id]);
    res.json({ requests: rows });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});

/* ═══════════════════════════════════════════════
   ADMIN  —  /api/admin/* (requires is_admin)
═══════════════════════════════════════════════ */
// Append-only admin audit log. Fire-and-forget: a logging failure must never block
// the action itself, but every mutating admin route calls this so there's always a
// record of who did what. `req` gives the actor + IP; `meta` carries action detail.
function adminAudit(req, action, targetType, targetId, meta) {
  try {
    if (!db.isConfigured()) return;
    const fwd = String(req.headers['x-forwarded-for'] || '').split(',')[0].trim();
    const ip = (fwd || req.ip || '').slice(0, 60);
    db.query(
      `INSERT INTO admin_audit (actor_id, actor_name, action, target_type, target_id, meta, ip)
       VALUES ($1, (SELECT name FROM users WHERE id = $1), $2, $3, $4, $5, $6)`,
      [req.user && req.user.id, action, targetType || null, targetId != null ? String(targetId) : null, meta || {}, ip]
    ).catch(() => {});
  } catch (_) { /* never throw from the audit path */ }
  // Also surface every staff action in the unified activity feed.
  logEvent('staff', action, { req, subjectType: targetType, subjectId: targetId, meta });
}

// Unified platform activity feed. Fire-and-forget: records a member/system/staff event
// so the superadmin's Activity page shows "everything that happened". Never throws.
function logEvent(category, action, opts = {}) {
  try {
    if (!db.isConfigured()) return;
    const actorId = opts.actorId != null ? opts.actorId : ((opts.req && opts.req.user && opts.req.user.id) || null);
    db.query(
      `INSERT INTO platform_events (category, action, actor_id, actor_name, subject_type, subject_id, subject_name, meta)
       VALUES ($1,$2,$3, COALESCE($4, (SELECT name FROM users WHERE id = $3)), $5,$6,$7,$8)`,
      [category, action, actorId, opts.actorName || null, opts.subjectType || null,
       opts.subjectId != null ? String(opts.subjectId) : null, opts.subjectName || null, opts.meta || {}]
    ).catch(() => {});
  } catch (_) { /* never throw from the activity path */ }
}

// Account enforcement status. `active` (normal), `suspended` (temporary — auto-lifts
// once suspended_until passes), `banned` (permanent). Returns a login-blocking message
// or null. Used at sign-in so a banned/suspended account can't get a fresh token; live
// sessions are separately revoked the moment the status is set.
const ACCOUNT_STATUSES = ['active', 'suspended', 'banned'];
// Staff permission scopes (RBAC). A superadmin (`is_admin`) implicitly has all; a
// scoped staff member is granted a subset. Each maps to a group of admin routes +
// dashboard tabs. Keep in sync with admin.html's TAB_PERM map.
const ADMIN_SCOPES = ['users', 'revenue', 'growth', 'ads', 'moderation', 'support', 'refunds', 'handles'];
function accountStatusBlock(row) {
  if (!row) return null;
  if (row.status === 'banned') {
    return row.status_reason ? `This account has been banned. Reason: ${row.status_reason}` : 'This account has been banned.';
  }
  if (row.status === 'suspended') {
    // A past suspension auto-lifts; the caller clears it lazily.
    if (row.suspended_until && new Date(row.suspended_until).getTime() <= Date.now()) return null;
    const until = row.suspended_until ? ` until ${new Date(row.suspended_until).toISOString().slice(0, 10)}` : '';
    return (row.status_reason ? `This account is suspended${until}. Reason: ${row.status_reason}` : `This account is suspended${until}.`);
  }
  return null;
}
// Lazily clear an expired suspension so the account transparently works again.
function clearExpiredSuspension(row) {
  if (row && row.status === 'suspended' && row.suspended_until && new Date(row.suspended_until).getTime() <= Date.now()) {
    db.query("UPDATE users SET status = 'active', suspended_until = NULL WHERE id = $1 AND status = 'suspended'", [row.id]).catch(() => {});
    return true;
  }
  return false;
}

app.get('/api/admin/users', auth.requirePerm('users'), async (_req, res) => {
  try {
    const { rows } = await db.query(`
      SELECT u.id, u.name, u.email, u.plan, u.is_admin, u.email_verified,
             u.username, u.avatar, u.created_at, u.last_login_at,
             u.verified, u.verify_requested_at, u.account_type, u.business_verify_status,
             u.status, u.status_reason, u.suspended_until, u.deactivated,
             u.wallet_frozen, u.wallet_frozen_reason,
             COUNT(c.id)::int AS chat_count,
             MAX(c.updated_at) AS last_chat_at,
             (SELECT COUNT(*)::int FROM admin_messages am
                WHERE am.user_id = u.id AND am.sender = 'user' AND am.read_by_admin = false) AS unread_msgs
      FROM users u
      LEFT JOIN chats c ON c.user_id = u.id
      GROUP BY u.id
      ORDER BY u.created_at DESC
    `);
    res.json({ users: rows });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

