// AtChat ACTIVITY for one user — counts + their PUBLIC posts only.
// Deliberately never exposes private DM or group message contents.
app.get('/api/admin/users/:id/atchat', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  try {
    const u = await db.query('SELECT id, name, username, avatar FROM users WHERE id = $1', [id]);
    if (!u.rows[0]) return res.status(404).json({ error: 'User not found.' });
    const s = await db.query(
      `SELECT
        (SELECT COUNT(*)::int FROM follows WHERE following_id = $1) AS followers,
        (SELECT COUNT(*)::int FROM follows WHERE follower_id  = $1) AS following,
        (SELECT COUNT(*)::int FROM posts   WHERE user_id      = $1) AS posts,
        (SELECT COUNT(DISTINCT CASE WHEN sender_id = $1 THEN recipient_id ELSE sender_id END)::int
           FROM at_messages WHERE sender_id = $1 OR recipient_id = $1) AS dm_people,
        (SELECT COUNT(*)::int FROM at_messages WHERE sender_id = $1) AS dm_sent,
        (SELECT COUNT(*)::int FROM at_group_members WHERE user_id = $1) AS groups,
        (SELECT COUNT(*)::int FROM at_group_messages WHERE sender_id = $1) AS group_sent`,
      [id]
    );
    const posts = await db.query(
      `SELECT p.id, p.body, p.image, p.created_at,
              (SELECT COUNT(*)::int FROM post_likes pl WHERE pl.post_id = p.id) AS likes
       FROM posts p WHERE p.user_id = $1 ORDER BY p.created_at DESC LIMIT 30`,
      [id]
    );
    res.json({
      user: { id: u.rows[0].id, name: u.rows[0].name, username: u.rows[0].username, avatar: u.rows[0].avatar || null },
      stats: s.rows[0],
      posts: posts.rows.map((p) => ({ id: p.id, body: p.body, image: p.image || null, created_at: p.created_at, likes: p.likes })),
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

// Read the admin ↔ user message thread (viewing clears the unread badge).
app.get('/api/admin/users/:id/messages', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  try {
    const u = await db.query('SELECT id, name, email FROM users WHERE id = $1', [id]);
    if (!u.rows[0]) return res.status(404).json({ error: 'User not found.' });
    const { rows } = await db.query(
      `SELECT id, sender, body, image, created_at FROM admin_messages
       WHERE user_id = $1 ORDER BY created_at ASC`,
      [id]
    );
    // The admin is actively viewing, so mark the user's replies as read.
    db.query(
      `UPDATE admin_messages SET read_by_admin = true
       WHERE user_id = $1 AND sender = 'user' AND read_by_admin = false`,
      [id]
    ).catch(() => {});
    res.json({ user: u.rows[0], messages: rows });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

// Admin sends a message to a user; also emails them a notification (best-effort).
app.post('/api/admin/users/:id/messages', auth.requirePerm('users'), rateLimit(60, 60000, 'admin-msg'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  const body = (req.body.body || '').trim();
  const image = cleanImage(req.body.image);
  if (image === undefined) return res.status(400).json({ error: 'That image could not be attached.' });
  if (!body && !image) return res.status(400).json({ error: 'Message cannot be empty.' });
  if (body.length > 5000) return res.status(400).json({ error: 'Message is too long.' });
  try {
    const u = await db.query('SELECT id, name, email FROM users WHERE id = $1', [id]);
    if (!u.rows[0]) return res.status(404).json({ error: 'User not found.' });
    const { rows } = await db.query(
      `INSERT INTO admin_messages (user_id, sender, body, image, read_by_user, read_by_admin)
       VALUES ($1, 'admin', $2, $3, false, true)
       RETURNING id, sender, body, image, created_at`,
      [id, body, image]
    );
    try {
      await sendAdminMessageEmail(u.rows[0], body || '📷 Photo');
    } catch (e) {
      console.error('Admin message email failed:', e.message);
    }
    res.json({ message: { ...rows[0], image: rows[0].image || null } });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

app.patch('/api/admin/users/:id', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  const fields = [];
  const values = [];
  if (req.body.plan === 'pro' || req.body.plan === 'free') {
    values.push(req.body.plan);
    fields.push(`plan = $${values.length}`);
  }
  if (typeof req.body.is_admin === 'boolean') {
    // Guard: an admin can't strip their own admin rights (avoid lockout).
    if (req.user.id === id && req.body.is_admin === false) {
      return res.status(400).json({ error: 'You cannot remove your own admin access.' });
    }
    values.push(req.body.is_admin);
    fields.push(`is_admin = $${values.length}`);
  }
  if (typeof req.body.email_verified === 'boolean') {
    values.push(req.body.email_verified);
    fields.push(`email_verified = $${values.length}`);
  }
  // Approve/revoke the verified badge. Either way the pending request is cleared.
  if (typeof req.body.verified === 'boolean') {
    values.push(req.body.verified);
    fields.push(`verified = $${values.length}`);
    fields.push('verify_requested_at = NULL');
  }
  // Business verification status: none | pending | verified.
  if (['none', 'pending', 'verified'].includes(req.body.businessVerifyStatus)) {
    values.push(req.body.businessVerifyStatus);
    fields.push(`business_verify_status = $${values.length}`);
  }
  if (!fields.length) return res.status(400).json({ error: 'Nothing to update.' });

  values.push(id);
  try {
    const { rows } = await db.query(
      `UPDATE users SET ${fields.join(', ')} WHERE id = $${values.length}
       RETURNING id, name, email, plan, is_admin, email_verified, verified, verify_requested_at, username, account_type, business_verify_status`,
      values
    );
    if (!rows[0]) return res.status(404).json({ error: 'User not found.' });
    adminAudit(req, 'user.update', 'user', id, { changes: req.body });
    // Return only the changed columns (no avatar/banner keys) so the client
    // merge can't blank out fields it didn't touch.
    res.json({ user: rows[0] });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

app.delete('/api/admin/users/:id', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  if (req.user.id === id) {
    return res.status(400).json({ error: 'You cannot delete your own account here.' });
  }
  try {
    const u = await db.query('SELECT name, email, username FROM users WHERE id = $1', [id]);
    await db.query('DELETE FROM users WHERE id = $1', [id]);
    adminAudit(req, 'user.delete', 'user', id, u.rows[0] || {});
    res.json({ ok: true });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

// Enforcement: suspend (temporary), ban (permanent), or reinstate an account.
// Distinct from delete — the account and its content stay, but the person is locked
// out. Live sessions are revoked immediately; login is blocked while suspended/banned.
app.post('/api/admin/users/:id/status', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  const status = String(req.body.status || '').trim();
  if (!ACCOUNT_STATUSES.includes(status)) return res.status(400).json({ error: 'status must be active, suspended or banned.' });
  if (req.user.id === id && status !== 'active') return res.status(400).json({ error: 'You cannot suspend or ban your own account.' });
  const reason = (req.body.reason ? String(req.body.reason) : '').slice(0, 500) || null;
  let suspendedUntil = null;
  if (status === 'suspended') {
    const days = Math.max(1, Math.min(3650, parseInt(req.body.days, 10) || 7));
    suspendedUntil = new Date(Date.now() + days * 86400000);
  }
  try {
    const target = await db.query('SELECT is_admin FROM users WHERE id = $1', [id]);
    if (!target.rows[0]) return res.status(404).json({ error: 'User not found.' });
    if (target.rows[0].is_admin && status !== 'active') return res.status(400).json({ error: 'Remove admin access before suspending or banning this account.' });
    const { rows } = await db.query(
      `UPDATE users SET status = $1, status_reason = $2, suspended_until = $3, status_by = $4, status_at = now()
       WHERE id = $5 RETURNING id, status, status_reason, suspended_until`,
      [status, reason, suspendedUntil, req.user.id, id]
    );
    // Lock them out now: drop every live session + realtime stream.
    if (status !== 'active') {
      await db.query('DELETE FROM auth_sessions WHERE user_id = $1', [id]).catch(() => {});
      rtKickUser(id);
    }
    adminAudit(req, status === 'active' ? 'user.reinstate' : ('user.' + status), 'user', id, { reason, suspendedUntil });
    res.json({ user: rows[0] });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

// Freeze / unfreeze a user's wallet (fraud hold). Blocks all OUTGOING money (send,
// cash-out, balance-paid orders/tips, splits, pools, rentals) while a case is looked
// at; incoming money still lands. Distinct from suspend/ban (which lock the whole
// account) — a freeze is money-only. Gated by the `users` scope; audit-logged.
app.post('/api/admin/users/:id/wallet-freeze', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  const frozen = req.body.frozen === true || req.body.frozen === 'true';
  const reason = (req.body.reason ? String(req.body.reason) : '').slice(0, 300) || null;
  try {
    const { rows } = await db.query(
      `UPDATE users SET wallet_frozen = $1, wallet_frozen_reason = $2 WHERE id = $3
       RETURNING id, wallet_frozen, wallet_frozen_reason`,
      [frozen, frozen ? reason : null, id]);
    if (!rows[0]) return res.status(404).json({ error: 'User not found.' });
    adminAudit(req, frozen ? 'wallet.freeze' : 'wallet.unfreeze', 'user', id, { reason });
    notify(id, req.user.id, frozen ? 'wallet_frozen' : 'wallet_unfrozen');
    res.json({ user: rows[0] });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});

// "View as user" — a fully-logged, time-boxed support impersonation. Returns a
// short-lived token (45m) for the member + the app URL to open. The session is
// recorded (who/whom/why/when) and irreversible actions are blocked while it's active.
app.post('/api/admin/users/:id/impersonate', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid user id.' });
  if (id === req.user.id) return res.status(400).json({ error: 'You can’t impersonate yourself.' });
  const reason = (req.body.reason ? String(req.body.reason) : '').slice(0, 300) || null;
  try {
    const target = (await db.query('SELECT id, name, username, email, is_admin FROM users WHERE id = $1', [id])).rows[0];
    if (!target) return res.status(404).json({ error: 'User not found.' });
    if (target.is_admin) return res.status(400).json({ error: 'You can’t view another admin’s account.' });
    const fwd = String(req.headers['x-forwarded-for'] || '').split(',')[0].trim();
    const ip = (fwd || req.ip || '').slice(0, 60);
    const sess = await db.query(
      `INSERT INTO impersonation_sessions (admin_id, admin_name, target_id, reason, ip, expires_at)
       VALUES ($1, (SELECT name FROM users WHERE id=$1), $2, $3, $4, now() + interval '45 minutes') RETURNING id`,
      [req.user.id, id, reason, ip]);
    const sid = sess.rows[0].id;
    const token = auth.signImpersonation(target, { by: req.user.id, sid });
    await createSession(target.id, token, req); // real, revocable session (shows in the member's devices)
    adminAudit(req, 'user.impersonate', 'user', id, { reason, sid });
    logEvent('staff', 'user.impersonate', { req, subjectType: 'user', subjectId: id, subjectName: target.name });
    const appUrl = (process.env.APP_URL || `${req.protocol}://${req.get('host')}`).replace(/\/$/, '') + '/?imp=' + encodeURIComponent(token);
    res.json({ token, appUrl, target: { id: target.id, name: target.name, username: target.username }, expiresInMin: 45 });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
// End an impersonation session early (the token also self-expires in 45m).
app.post('/api/admin/impersonation/:id/end', auth.requirePerm('users'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid id.' });
  try {
    await db.query('UPDATE impersonation_sessions SET ended_at = now() WHERE id = $1 AND ended_at IS NULL', [id]);
    res.json({ ok: true });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
// Recent impersonation sessions (the accountability record).
