// ─── Admin: Refunds queue (staff `refunds` scope) ───
app.get('/api/admin/refunds', auth.requirePerm('refunds'), async (req, res) => {
  const status = ['open', 'approved', 'declined'].includes(req.query.status) ? req.query.status : null;
  try {
    const { rows } = await db.query(
      `SELECT r.id, r.kind, r.ref_id, r.amount_cents, r.reason, r.status, r.resolution_note,
              r.refunded_cents, r.created_at, r.resolved_at,
              u.name AS user_name, u.username AS user_username, u.email AS user_email, u.id AS user_id,
              b.name AS resolved_by_name
       FROM refund_requests r JOIN users u ON u.id = r.user_id LEFT JOIN users b ON b.id = r.resolved_by
       ${status ? 'WHERE r.status = $1' : ''}
       ORDER BY (r.status = 'open') DESC, r.created_at DESC LIMIT 200`,
      status ? [status] : []);
    const openCount = await db.query(`SELECT COUNT(*)::int AS n FROM refund_requests WHERE status = 'open'`).then(x => x.rows[0].n).catch(() => 0);
    res.json({ requests: rows, openCount });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});
// Approve (money reversed to the member's wallet) or decline a refund request.
app.post('/api/admin/refunds/:id/resolve', auth.requirePerm('refunds'), async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!Number.isInteger(id)) return res.status(400).json({ error: 'Invalid id.' });
  const action = req.body.action === 'approve' ? 'approve' : req.body.action === 'decline' ? 'decline' : null;
  if (!action) return res.status(400).json({ error: 'Choose approve or decline.' });
  const note = (req.body.note ? String(req.body.note) : '').slice(0, 500) || null;
  try {
    // Claim the request first (status guard) so two staff can't double-refund.
    const claimed = await db.query(`UPDATE refund_requests SET status = 'resolving' WHERE id = $1 AND status = 'open' RETURNING *`, [id]);
    const rr = claimed.rows[0];
    if (!rr) return res.status(409).json({ error: 'That request was already handled.' });
    if (action === 'decline') {
      await db.query(`UPDATE refund_requests SET status='declined', resolution_note=$2, resolved_by=$3, resolved_at=now() WHERE id=$1`, [id, note, req.user.id]);
      adminAudit(req, 'refund.decline', 'refund', id, { kind: rr.kind, refId: rr.ref_id });
      notify(rr.user_id, req.user.id, 'refund_declined');
      return res.json({ ok: true, status: 'declined' });
    }
    // Approve: staff can confirm/override the amount (defaults to the requested amount).
    let amount = parseInt(req.body.amountCents, 10);
    if (!Number.isInteger(amount) || amount <= 0) amount = rr.amount_cents;
    amount = Math.min(amount, Math.max(rr.amount_cents, 0) || amount); // never refund more than paid
    if (!amount || amount <= 0) { await db.query(`UPDATE refund_requests SET status='open' WHERE id=$1`, [id]); return res.status(400).json({ error: 'Nothing to refund on this payment.' }); }
    try {
      await executeRefund(rr, amount, req.user.id);
    } catch (e) {
      await db.query(`UPDATE refund_requests SET status='open' WHERE id=$1`, [id]).catch(() => {});
      console.error('refund exec failed:', e.message);
      return res.status(500).json({ error: 'Could not move the money. Try again.' });
    }
    await db.query(`UPDATE refund_requests SET status='approved', refunded_cents=$2, resolution_note=$3, resolved_by=$4, resolved_at=now() WHERE id=$1`, [id, amount, note, req.user.id]);
    adminAudit(req, 'refund.approve', 'refund', id, { kind: rr.kind, refId: rr.ref_id, amountCents: amount });
    notify(rr.user_id, req.user.id, 'refund_approved');
    res.json({ ok: true, status: 'approved', refundedCents: amount });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Something went wrong. Please try again.' }); }
});

// ─── Admin: Finance oversight — the "money is safe + reconciled" screen ───
// Shows the total custodial float (all user balances + pots + escrow held), wallet
// throughput, cash-outs/payouts, refunds, open disputes, and the recent ledger.
app.get('/api/admin/finance', auth.requirePerm('revenue'), async (_req, res) => {
  const one = (sql, def) => db.query(sql).then(r => r.rows[0]).catch(() => def);
  const num = (v) => parseInt(v, 10) || 0;
  try {
    const balances = await one(`SELECT COALESCE(SUM(balance_cents),0)::bigint AS bal, COUNT(*) FILTER (WHERE balance_cents > 0)::int AS funded FROM users`, {});
    const pots = await one(`SELECT COALESCE(SUM(balance_cents),0)::bigint AS bal FROM wallet_pots`, {});
    // Net escrow still held = holds debited from buyers minus anything released/refunded.
    const escrow = await one(`SELECT
        COALESCE(SUM(CASE WHEN kind='escrow_hold' THEN -delta_cents ELSE 0 END),0)
      - COALESCE(SUM(CASE WHEN kind IN ('escrow_release','escrow_refund') THEN delta_cents ELSE 0 END),0) AS held FROM wallet_tx`, {});
    const vol = await one(`SELECT
        COALESCE(SUM(CASE WHEN delta_cents<0 AND created_at>now()-interval '1 day'  THEN -delta_cents ELSE 0 END),0)::bigint AS d1,
        COALESCE(SUM(CASE WHEN delta_cents<0 AND created_at>now()-interval '7 days' THEN -delta_cents ELSE 0 END),0)::bigint AS d7,
        COALESCE(SUM(CASE WHEN delta_cents<0 AND created_at>now()-interval '30 days' THEN -delta_cents ELSE 0 END),0)::bigint AS d30,
        COUNT(*)::int AS txn FROM wallet_tx`, {});
    const cash = await one(`SELECT COUNT(*)::int AS n, COALESCE(SUM(-delta_cents),0)::bigint AS total FROM wallet_tx WHERE kind='cashout'`, {});
    const payouts = await one(`SELECT COUNT(*) FILTER (WHERE connect_payouts_enabled)::int AS enabled, COUNT(*) FILTER (WHERE stripe_connect_id IS NOT NULL)::int AS connected FROM users`, {});
    const refunds = await one(`SELECT COUNT(*)::int AS n FROM order_returns WHERE status='refunded'`, {});
    const orders = await one(`SELECT
        COUNT(*) FILTER (WHERE status='disputed')::int AS disputed,
        COUNT(*) FILTER (WHERE status='escrow')::int AS escrow,
        COUNT(*) FILTER (WHERE status='pending')::int AS pending FROM orders`, {});
    const topBalances = await db.query(`SELECT id, name, username, balance_cents FROM users WHERE balance_cents > 0 ORDER BY balance_cents DESC LIMIT 10`).then(r => r.rows).catch(() => []);
    const recent = await db.query(
      `SELECT w.id, w.kind, w.delta_cents, w.balance_after, w.created_at,
              u.name AS user_name, u.username AS user_username,
              p.name AS peer_name, p.username AS peer_username
       FROM wallet_tx w LEFT JOIN users u ON u.id = w.user_id LEFT JOIN users p ON p.id = w.peer_id
       ORDER BY w.created_at DESC LIMIT 40`).then(r => r.rows).catch(() => []);
    const floatCents = num(balances.bal) + num(pots.bal) + num(escrow && escrow.held);
    res.json({
      floatCents,
      userBalanceCents: num(balances.bal), potsCents: num(pots.bal), escrowHeldCents: num(escrow && escrow.held),
      fundedWallets: num(balances.funded),
      volume: { d1: num(vol.d1), d7: num(vol.d7), d30: num(vol.d30), txns: num(vol.txn) },
      cashouts: { count: num(cash.n), totalCents: num(cash.total) },
      payouts: { enabled: num(payouts.enabled), connected: num(payouts.connected) },
      refunds: num(refunds.n),
      orders: { disputed: num(orders.disputed), escrow: num(orders.escrow), pending: num(orders.pending) },
      topBalances, recent,
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

// ─── Admin: Growth analytics — signups, active users (DAU/WAU/MAU), retention ───
app.get('/api/admin/growth', auth.requirePerm('growth'), async (_req, res) => {
  const num = (v) => parseInt(v, 10) || 0;
  try {
    const signups = await db.query(`SELECT
        COUNT(*)::int AS total,
        COUNT(*) FILTER (WHERE created_at > now()-interval '1 day')::int  AS d1,
        COUNT(*) FILTER (WHERE created_at > now()-interval '7 days')::int  AS d7,
        COUNT(*) FILTER (WHERE created_at > now()-interval '30 days')::int AS d30,
        COUNT(*) FILTER (WHERE account_type='business')::int AS businesses,
        COUNT(*) FILTER (WHERE verified)::int AS verified,
        COUNT(*) FILTER (WHERE status='suspended')::int AS suspended,
        COUNT(*) FILTER (WHERE status='banned')::int AS banned
      FROM users`).then(r => r.rows[0]).catch(() => ({}));
    // Active users from live sessions (auth_sessions.last_seen tracks real activity).
    const active = await db.query(`SELECT
        COUNT(DISTINCT user_id) FILTER (WHERE last_seen > now()-interval '1 day')::int  AS dau,
        COUNT(DISTINCT user_id) FILTER (WHERE last_seen > now()-interval '7 days')::int  AS wau,
        COUNT(DISTINCT user_id) FILTER (WHERE last_seen > now()-interval '30 days')::int AS mau
      FROM auth_sessions`).then(r => r.rows[0]).catch(() => ({ dau: 0, wau: 0, mau: 0 }));
    // 30-day zero-filled signup trend.
    const trend = await db.query(`
      SELECT to_char(d.day,'YYYY-MM-DD') AS day, COALESCE(c.n,0)::int AS n
      FROM generate_series((now()-interval '29 days')::date, now()::date, interval '1 day') d(day)
      LEFT JOIN (SELECT created_at::date AS day, COUNT(*) AS n FROM users GROUP BY 1) c ON c.day = d.day
      ORDER BY d.day`).then(r => r.rows).catch(() => []);
    const mau = num(active.mau);
    res.json({
      signups: { total: num(signups.total), d1: num(signups.d1), d7: num(signups.d7), d30: num(signups.d30) },
      accounts: { businesses: num(signups.businesses), verified: num(signups.verified), suspended: num(signups.suspended), banned: num(signups.banned) },
      active: { dau: num(active.dau), wau: num(active.wau), mau },
      stickiness: mau ? Math.round((num(active.dau) / mau) * 1000) / 10 : 0, // DAU/MAU %
      trend,
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Something went wrong. Please try again.' });
  }
});

/* ─── Admin: platform overview metrics ─── */
app.get('/api/admin/stats', auth.requireAdmin, async (_req, res) => {
  const c = (sql) => db.query(sql).then(r => parseInt(r.rows[0].c, 10) || 0).catch(() => 0);
  try {
    const [users, pro, admins, verified, withUsername, newToday, new7d,
           posts, replies, circles, groups, dms, calls, locks] = await Promise.all([
      c(`SELECT COUNT(*) c FROM users`),
      c(`SELECT COUNT(*) c FROM users WHERE plan = 'pro'`),
      c(`SELECT COUNT(*) c FROM users WHERE is_admin`),
      c(`SELECT COUNT(*) c FROM users WHERE email_verified`),
      c(`SELECT COUNT(*) c FROM users WHERE username IS NOT NULL`),
      c(`SELECT COUNT(*) c FROM users WHERE created_at > now() - interval '1 day'`),
      c(`SELECT COUNT(*) c FROM users WHERE created_at > now() - interval '7 days'`),
      c(`SELECT COUNT(*) c FROM posts WHERE parent_id IS NULL`),
      c(`SELECT COUNT(*) c FROM posts WHERE parent_id IS NOT NULL`),
      c(`SELECT COUNT(*) c FROM circles`),
      c(`SELECT COUNT(*) c FROM at_groups`),
      c(`SELECT COUNT(*) c FROM at_messages`),
      c(`SELECT COUNT(*) c FROM calls`),
      c(`SELECT COUNT(*) c FROM reserved_usernames`),
    ]);
    res.json({ stats: { users, pro, free: users - pro, admins, verified, withUsername,
      newToday, new7d, posts, replies, circles, groups, dms, calls, locks } });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not load stats.' });
  }
});

// Admin diagnostic: which TURN provider is live for calls, and (for Cloudflare)
// whether credentials actually mint successfully right now.
app.get('/api/admin/turn', auth.requireAdmin, async (_req, res) => {
  if (process.env.CLOUDFLARE_TURN_KEY_ID && process.env.CLOUDFLARE_TURN_API_TOKEN) {
    try {
      const s = await cloudflareTurnServer();
      return res.json({ provider: 'cloudflare', ok: !!(s && s.urls), urls: s ? s.urls : null });
    } catch (e) {
      return res.json({ provider: 'cloudflare', ok: false, error: e.message });
    }
  }
  if (process.env.TURN_URL) {
    return res.json({ provider: 'static', ok: true, urls: process.env.TURN_URL.split(',').map((s) => s.trim()).filter(Boolean) });
  }
  res.json({ provider: 'fallback', ok: true, urls: ['turn:openrelay.metered.ca:443'] });
});

/* ─── Admin: username locks (reserved usernames) ─── */
// Paginated + searchable — the reserved list can run to thousands of names once
// the premium/short-combo tiers are seeded, so never dump the whole table.
app.get('/api/admin/username-locks', auth.requirePerm('handles'), async (req, res) => {
  const q = (req.query.q || '').toString().trim().toLowerCase().replace(/^@/, '');
  const limit = Math.min(500, Math.max(1, parseInt(req.query.limit, 10) || 100));
  const offset = Math.max(0, parseInt(req.query.offset, 10) || 0);
  try {
    const where = q ? `WHERE r.username LIKE $1` : '';
    const like = '%' + q.replace(/[%_\\]/g, '\\$&') + '%';
    const params = q ? [like] : [];
    const total = (await db.query(`SELECT count(*)::int AS n FROM reserved_usernames r ${where}`, params)).rows[0].n;
    const grand = q ? (await db.query('SELECT count(*)::int AS n FROM reserved_usernames')).rows[0].n : total;
    const { rows } = await db.query(
      `SELECT r.username, r.note, r.created_at, r.price_cents,
              EXISTS(SELECT 1 FROM users u WHERE lower(u.username) = r.username) AS taken
       FROM reserved_usernames r ${where}
       ORDER BY length(r.username), r.username
       LIMIT ${limit} OFFSET ${offset}`,
      params
    );
    res.json({ locks: rows, total, grandTotal: grand, limit, offset });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not load username locks.' });
  }
});
// Bulk-lock many usernames at once (paste-a-list or programmatic). Skips ones
// already locked; validates + de-dupes. Returns how many were newly added.
app.post('/api/admin/username-locks/bulk', auth.requirePerm('handles'), async (req, res) => {
  const note = ((req.body.note || '').toString().trim().slice(0, 200)) || null;
  let names = req.body.usernames;
  if (typeof names === 'string') names = names.split(/[\s,]+/);
  if (!Array.isArray(names)) return res.status(400).json({ error: 'Provide a list of usernames.' });
  const clean = [...new Set(
    names.map((n) => String(n || '').trim().replace(/^@/, '').toLowerCase())
      .filter((n) => n && n.length <= 40 && /^[a-z0-9._-]+$/.test(n))
  )].slice(0, 50000); // one call caps at 50k; the seed loops for bigger tiers
  if (!clean.length) return res.status(400).json({ error: 'No valid usernames to lock.' });
  const price = parseHandlePrice(req.body.priceCents);
  try {
    const added = await bulkLockUsernames(clean, note, req.user.id, price);
    res.json({ ok: true, requested: clean.length, added });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not lock those usernames.' });
  }
});
// Seed a whole tier (curated premium names and/or every short 1–4 char combo).
// The heavy tiers (len3/len4) are big — the client shows the count + a warning
// before calling. Inserts in chunks so a huge tier doesn't build one giant query.
app.post('/api/admin/username-locks/seed', auth.requirePerm('handles'), async (req, res) => {
  const tiers = {
    curated: !!req.body.curated,
    len1: !!req.body.len1, len2: !!req.body.len2, len3: !!req.body.len3, len4: !!req.body.len4,
  };
  if (!Object.values(tiers).some(Boolean)) return res.status(400).json({ error: 'Pick at least one tier to seed.' });
  const price = parseHandlePrice(req.body.priceCents);
  try {
    const list = reservedSeed.buildReservedList(tiers);
    let added = 0;
    for (let i = 0; i < list.length; i += 5000) {
      added += await bulkLockUsernames(list.slice(i, i + 5000), 'Seeded (premium/short)', req.user.id, price);
    }
    res.json({ ok: true, requested: list.length, added });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not seed the reserved names.' });
  }
});
// Assign (grant) a reserved name to a specific account — the "give it to the
// legitimate owner" flow. Sets that user's username to the reserved name (freeing
// their old handle) and removes the lock. Fails if the name is already held.
app.post('/api/admin/username-locks/:username/assign', auth.requirePerm('handles'), async (req, res) => {
  const username = (req.params.username || '').trim().replace(/^@/, '').toLowerCase();
  const toRaw = (req.body.toUsername || req.body.to || '').toString().trim().replace(/^@/, '');
  const toId = parseInt(req.body.toId, 10);
  if (!username) return res.status(400).json({ error: 'No username given.' });
  try {
    const held = (await db.query('SELECT id FROM users WHERE lower(username) = $1', [username])).rows[0];
    if (held) return res.status(409).json({ error: 'That name is already held by an account. Unlock it or pick another.' });
    let target;
    if (Number.isInteger(toId)) target = (await db.query('SELECT id, username FROM users WHERE id = $1', [toId])).rows[0];
    else if (toRaw) target = (await db.query('SELECT id, username FROM users WHERE lower(username) = lower($1)', [toRaw])).rows[0];
    if (!target) return res.status(404).json({ error: 'No account found to assign it to.' });
    // Move the handle onto the target account and drop the reservation atomically.
    await db.query('BEGIN');
    await db.query('UPDATE users SET username = $1 WHERE id = $2', [username, target.id]);
    await db.query('DELETE FROM reserved_usernames WHERE username = $1', [username]);
    await db.query('COMMIT');
    adminAudit(req, 'handle.assign', 'user', target.id, { username, previousUsername: target.username });
    res.json({ ok: true, username, assignedTo: { id: target.id, previousUsername: target.username } });
  } catch (err) {
    await db.query('ROLLBACK').catch(() => {});
    console.error(err);
    res.status(500).json({ error: 'Could not assign that username.' });
  }
});
app.post('/api/admin/username-locks', auth.requirePerm('handles'), async (req, res) => {
  const username = (req.body.username || '').trim().replace(/^@/, '').toLowerCase();
  const note = ((req.body.note || '').trim().slice(0, 200)) || null;
  if (!username) return res.status(400).json({ error: 'Enter a username to lock.' });
  if (username.length > 40) return res.status(400).json({ error: 'Username is too long.' });
  if (!/^[a-z0-9._-]+$/.test(username)) {
    return res.status(400).json({ error: 'Username can use letters, numbers, dots, dashes and underscores.' });
  }
  const price = parseHandlePrice(req.body.priceCents);
  try {
    await db.query(
      `INSERT INTO reserved_usernames (username, note, created_by, price_cents) VALUES ($1, $2, $3, $4)
       ON CONFLICT (username) DO UPDATE SET note = EXCLUDED.note, price_cents = EXCLUDED.price_cents`,
      [username, note, req.user.id, price]
    );
    const taken = await db.query('SELECT 1 FROM users WHERE lower(username) = $1', [username]);
    res.json({ ok: true, lock: { username, note, priceCents: price, created_at: new Date().toISOString(), taken: taken.rowCount > 0 } });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not lock that username.' });
  }
});
// Set (or clear) the self-serve sale price on a reserved handle. priceCents > 0
// puts it on sale (any member can buy it from their wallet); null/0 takes it off
// sale (admin-grant only).
app.patch('/api/admin/username-locks/:username', auth.requirePerm('handles'), async (req, res) => {
  const username = (req.params.username || '').trim().replace(/^@/, '').toLowerCase();
  const price = parseHandlePrice(req.body.priceCents);
  try {
    const r = await db.query('UPDATE reserved_usernames SET price_cents = $2 WHERE username = $1 RETURNING username', [username, price]);
    if (!r.rowCount) return res.status(404).json({ error: 'That name isn’t reserved.' });
    res.json({ ok: true, username, priceCents: price });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not update the price.' });
  }
});
app.delete('/api/admin/username-locks/:username', auth.requirePerm('handles'), async (req, res) => {
  const username = (req.params.username || '').trim().replace(/^@/, '').toLowerCase();
  try {
    await db.query('DELETE FROM reserved_usernames WHERE username = $1', [username]);
    res.json({ ok: true });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not unlock that username.' });
  }
});

/* ─── Self-serve paid handle claim (buy a premium @handle from wallet balance) ─── */
// Atomically: verify the buyer can afford it, the name is still on sale AND not
// held by anyone, then debit the wallet, set the buyer's username to it, and drop
// the reservation — all in ONE transaction so a crash/race can never charge without
// assigning (or assign without charging). Balance-funded (top up via Stripe first),
// consistent with splits/gift-cards/pools/escrow; no Stripe double-pay race.
async function claimHandleFromBalance(buyerId, username, expectedPrice) {
  const client = await db.getPool().connect();
  try {
    await client.query('BEGIN');
    const b = (await client.query('SELECT balance_cents FROM users WHERE id = $1 FOR UPDATE', [buyerId])).rows[0];
    if (!b) { await client.query('ROLLBACK'); return { error: 'nouser' }; }
    const r = (await client.query('SELECT price_cents FROM reserved_usernames WHERE username = $1 FOR UPDATE', [username])).rows[0];
    if (!r || r.price_cents == null) { await client.query('ROLLBACK'); return { notForSale: true }; }
    const price = r.price_cents;
    if (expectedPrice != null && expectedPrice !== price) { await client.query('ROLLBACK'); return { priceChanged: true, priceCents: price }; }
    const held = await client.query('SELECT 1 FROM users WHERE lower(username) = lower($1)', [username]);
    if (held.rowCount) { await client.query('ROLLBACK'); return { taken: true }; }
    if (b.balance_cents < price) { await client.query('ROLLBACK'); return { insufficient: true, priceCents: price }; }
    await walletCredit(client, buyerId, -price, 'handle', null, 'Claimed @' + username);
    await client.query('UPDATE users SET username = $1 WHERE id = $2', [username, buyerId]);
    await client.query('DELETE FROM reserved_usernames WHERE username = $1', [username]);
    await client.query('COMMIT');
    return { ok: true, priceCents: price };
  } catch (e) {
    await client.query('ROLLBACK').catch(() => {});
    // A unique-violation on the username UPDATE means someone claimed the same
    // name in the tiny window after our held-check — surface it as "taken" (a
    // clean 409) rather than a generic 500. Money already rolled back.
    if (e && e.code === '23505') return { taken: true };
    throw e;
  } finally {
    client.release();
  }
}
// Is this @handle a self-serve paid claim for the caller? (reserved + priced + not
// currently held). Returns { claimable, priceCents, reason }.
app.get('/api/handles/:username', auth.requireAuth, async (req, res) => {
  const username = (req.params.username || '').trim().replace(/^@/, '').toLowerCase();
  if (!username || !/^[a-z0-9._-]{1,40}$/.test(username)) return res.status(400).json({ error: 'Enter a valid username.' });
  try {
    const held = await db.query('SELECT 1 FROM users WHERE lower(username) = $1', [username]);
    if (held.rowCount) return res.json({ username, claimable: false, reason: 'taken' });
    const r = (await db.query('SELECT price_cents FROM reserved_usernames WHERE username = $1', [username])).rows[0];
    if (!r) return res.json({ username, claimable: false, reason: 'available' }); // not reserved → normal signup/change path
    if (r.price_cents == null) return res.json({ username, claimable: false, reason: 'reserved' }); // reserved, not for sale
    res.json({ username, claimable: true, priceCents: r.price_cents });
  } catch (err) { console.error(err); res.status(500).json({ error: 'Could not check that handle.' }); }
});
// Buy an on-sale reserved @handle from wallet balance and switch to it.
app.post('/api/handles/claim', auth.requireAuth, rateLimit(15, 60000, 'handle-claim'), async (req, res) => {
  const username = (req.body.username || '').trim().replace(/^@/, '').toLowerCase();
  if (!username || !/^[a-z0-9._-]{1,40}$/.test(username)) return res.status(400).json({ error: 'Enter a valid username.' });
  const expectedPrice = parseHandlePrice(req.body.priceCents); // optional client-quoted price (guards a price change)
  const cid = req.body.clientId;
  try {
    // A handle buy is wallet outflow, so it counts toward the anti-fraud velocity
    // caps like send/tip/order do. Price comes from the DB (re-validated atomically
    // in the claim); this check is a soft ceiling, run before the money move.
    const priceRow = (await db.query('SELECT price_cents FROM reserved_usernames WHERE username = $1', [username])).rows[0];
    if (!priceRow || priceRow.price_cents == null) return res.status(400).json({ error: 'That handle isn’t for sale.' });
    const vel = await walletVelocityCheck(req.user.id, priceRow.price_cents);
    if (!vel.ok) return res.status(429).json(walletVelocityError(vel));
    const idem = await walletClaimIdem(req.user.id, cid, 'handle');
    if (!idem.claimed) return res.json(idem.result || { ok: true, username, deduped: true });
    const r = await claimHandleFromBalance(req.user.id, username, expectedPrice);
    if (!r.ok) {
      await walletReleaseIdem(req.user.id, cid, 'handle');
      if (r.insufficient) return res.status(400).json({ error: 'Not enough wallet balance. Add money and try again.', insufficientBalance: true, priceCents: r.priceCents });
      if (r.taken) return res.status(409).json({ error: 'That handle was just taken.' });
      if (r.notForSale) return res.status(400).json({ error: 'That handle isn’t for sale.' });
      if (r.priceChanged) return res.status(409).json({ error: 'The price just changed.', priceChanged: true, priceCents: r.priceCents });
      return res.status(400).json({ error: 'Could not claim that handle.' });
    }
    const result = { ok: true, username, paidCents: r.priceCents };
    await walletStoreIdem(req.user.id, cid, 'handle', result);
    rtPush(req.user.id, 'wallet', { type: 'update', amountCents: r.priceCents });
    res.json(result);
  } catch (err) {
    await walletReleaseIdem(req.user.id, req.body.clientId, 'handle').catch(() => {});
    console.error(err);
    res.status(500).json({ error: 'Could not claim that handle.' });
  }
});

/* ─── Admin: site traffic analytics ─── */
// Views + unique visitors + a zero-filled trend + top locations, for a chosen
// window. All interval/bucket/series values come from a fixed whitelist keyed by
// `range`, so nothing from the request is interpolated into SQL.
app.get('/api/admin/analytics', auth.requirePerm('growth'), async (req, res) => {
  const range = ['today', 'week', 'year'].includes(req.query.range) ? req.query.range : 'week';
  const spec = {
    today: { interval: '1 day', bucket: 'hour', series: 24 },
    week: { interval: '7 days', bucket: 'day', series: 7 },
    year: { interval: '1 year', bucket: 'month', series: 12 },
  }[range];
  const since = `now() - interval '${spec.interval}'`;
  const bk = spec.bucket;
  try {
    const totals = (await db.query(`SELECT count(*)::int AS views, count(DISTINCT visitor)::int AS visitors FROM page_views WHERE created_at >= ${since}`)).rows[0];
    const previous = (await db.query(`SELECT count(*)::int AS views, count(DISTINCT visitor)::int AS visitors FROM page_views WHERE created_at >= ${since} - interval '${spec.interval}' AND created_at < ${since}`)).rows[0];
    const live = (await db.query(`SELECT count(DISTINCT visitor)::int AS n FROM page_views WHERE created_at >= now() - interval '5 minutes'`)).rows[0].n;
    const allTime = (await db.query(`SELECT count(*)::int AS views, count(DISTINCT visitor)::int AS visitors FROM page_views`)).rows[0];
    // One scan, zero-filled against a generated bucket series.
    const trend = (await db.query(
      `WITH g AS (
         SELECT date_trunc('${bk}', created_at) AS b, count(*)::int AS views, count(DISTINCT visitor)::int AS visitors
         FROM page_views WHERE created_at >= ${since} GROUP BY 1
       )
       SELECT s.b AS bucket, COALESCE(g.views, 0) AS views, COALESCE(g.visitors, 0) AS visitors
       FROM generate_series(
         date_trunc('${bk}', now()) - interval '${spec.series - 1} ${bk}',
         date_trunc('${bk}', now()), interval '1 ${bk}'
       ) s(b) LEFT JOIN g ON g.b = s.b
       ORDER BY s.b`
    )).rows;
    const countries = (await db.query(
      `SELECT COALESCE(NULLIF(g.country, ''), 'Unknown') AS country,
              count(*)::int AS views, count(DISTINCT pv.visitor)::int AS visitors
       FROM page_views pv LEFT JOIN ip_geo g ON g.ip = pv.ip
       WHERE pv.created_at >= ${since}
       GROUP BY 1 ORDER BY views DESC LIMIT 12`
    )).rows;
    const cities = (await db.query(
      `SELECT g.city, COALESCE(NULLIF(g.country, ''), '') AS country, count(*)::int AS views
       FROM page_views pv JOIN ip_geo g ON g.ip = pv.ip
       WHERE pv.created_at >= ${since} AND g.city IS NOT NULL AND g.city <> ''
       GROUP BY 1, 2 ORDER BY views DESC LIMIT 12`
    )).rows;
    res.json({ range, bucket: bk, totals, previous, live, allTime, trend, countries, cities, geoEnabled: geoip.isConfigured() });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Could not load analytics.' });
  }
});

